INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5419, 'baidu-hot', '李子柒编剧纪录片《温室》过审', 'https://www.baidu.com/s?wd=%E6%9D%8E%E5%AD%90%E6%9F%92%E7%BC%96%E5%89%A7%E7%BA%AA%E5%BD%95%E7%89%87%E3%80%8A%E6%B8%A9%E5%AE%A4%E3%80%8B%E8%BF%87%E5%AE%A1&sa=fyb_news&rsv_dl=fyb_news', '3402570', 225, '', '近日，李子柒担任编剧的纪录片《温室》已通过国家电影局备案，备案号为影纪备字〔2026〕第30号。该片讲述其为患病奶奶建造温室的故事。此前李子柒曾表示，希望多一些时间陪伴奶奶，回归更纯粹的生活状态。', '2026-03-31T02:04:09.664Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6750, 'baidu-hot', '用无人机吊人上山 警方警告并罚款', 'https://www.baidu.com/s?wd=%E7%94%A8%E6%97%A0%E4%BA%BA%E6%9C%BA%E5%90%8A%E4%BA%BA%E4%B8%8A%E5%B1%B1+%E8%AD%A6%E6%96%B9%E8%AD%A6%E5%91%8A%E5%B9%B6%E7%BD%9A%E6%AC%BE&sa=fyb_news&rsv_dl=fyb_news', '4450765', 132, '', '近日，重庆奉节县某柑橘园操作员郑某违规使用农用无人机吊运人员上山，离地高度超10米。日前，大疆公司吊销其操作证书并禁飞1年，当地警方对郑某处以警告和罚款。', '2026-03-31T23:05:26.297Z');
