INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5616, 'baidu-hot', '妻子14岁起陪张雪白手起家', 'https://www.baidu.com/s?wd=%E5%A6%BB%E5%AD%9014%E5%B2%81%E8%B5%B7%E9%99%AA%E5%BC%A0%E9%9B%AA%E7%99%BD%E6%89%8B%E8%B5%B7%E5%AE%B6&sa=fyb_news&rsv_dl=fyb_news', '7807968', 3, '', '近日，张雪机车在世界超级摩托车锦标赛两天两冠，引发大量关注。2013年，张雪与妻子李婷带着仅有的2万元积蓄从湖南怀化赴重庆创业。李婷从张雪14岁做修车学徒时便相伴左右，25年不离不弃支持其创业。', '2026-03-31T01:25:26.445Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5861, 'baidu-hot', '中方：对伊朗文物古迹遭破坏深感痛惜', 'https://www.baidu.com/s?wd=%E4%B8%AD%E6%96%B9%EF%BC%9A%E5%AF%B9%E4%BC%8A%E6%9C%97%E6%96%87%E7%89%A9%E5%8F%A4%E8%BF%B9%E9%81%AD%E7%A0%B4%E5%9D%8F%E6%B7%B1%E6%84%9F%E7%97%9B%E6%83%9C&sa=fyb_news&rsv_dl=fyb_news', '3783849', 182, '', '3月31日，外交部发言人毛宁在例行记者会上答问时表示，中方对伊朗的文物古迹在战争中遭受破坏深感痛惜，敦促交战各方特别是美国和以色列立即全面停止军事行动，尽快启动对话谈判，尽早结束这场本不应该发生的战争。', '2026-03-31T16:04:21.744Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6425, 'baidu-hot', '“81192 无论何时我们等你回家”', 'https://www.baidu.com/s?wd=%E2%80%9C81192+%E6%97%A0%E8%AE%BA%E4%BD%95%E6%97%B6%E6%88%91%E4%BB%AC%E7%AD%89%E4%BD%A0%E5%9B%9E%E5%AE%B6%E2%80%9D&sa=fyb_news&rsv_dl=fyb_news', '3701237', 188, '', '回看25年前的《新闻联播》，搜寻“海空卫士”王伟的画面还历历在目。那年四月，他为保卫祖国领空遭美机撞机被迫跳伞坠海牺牲，年仅33岁。该消息牵动了我们所有人的心……81192，无论何时，我们等你回家！', '2026-03-31T16:04:21.744Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6426, 'baidu-hot', '民警街头抓捕盗窃犯 这一飞扑太帅了', 'https://www.baidu.com/s?wd=%E6%B0%91%E8%AD%A6%E8%A1%97%E5%A4%B4%E6%8A%93%E6%8D%95%E7%9B%97%E7%AA%83%E7%8A%AF+%E8%BF%99%E4%B8%80%E9%A3%9E%E6%89%91%E5%A4%AA%E5%B8%85%E4%BA%86&sa=fyb_news&rsv_dl=fyb_news', '3484933', 216, '', '近日，民警街头抓捕盗窃嫌疑人，分工合作一气呵成。画面显示，两名巡警在嫌疑人后方追捕，派出所民警开车前方包抄。民警一个飞扑，嫌疑人当场被制服！网友：这一飞扑太帅了！', '2026-03-31T16:04:21.744Z');
