INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6400, 'tencent-hot', '武汉萝卜快跑集体“瘫痪”？有乘客被困高架近两小时，客服称系网络原因导致', 'https://view.inews.qq.com/a/20260401A00K6H00', '0', 142, '', '3月31日21时许，多名IP地址为湖北的网友发帖称，武汉萝卜快跑集体瘫痪，有多名乘客称被困在高架上或主干道上。同日晚，萝卜快跑客服称，车辆驾驶系统异常是网络原因导致。“（车）直接在三环线上路中间停了，两边全是大货车，车子开得飞快。”3月31日22时40分许，武汉网友鲁先生告诉读特记者，他仍在萝卜快跑的车上，已经被...', '2026-03-31T16:04:03.544Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6256, 'tencent-hot', '民航局航安办公布多起事件调查报告，涉及试飞体验项目、南方电网直升机、农用飞机等', 'https://view.inews.qq.com/a/20260331A03KZZ00', '0', 104, '', '2026年2月，中国民用航空局航空安全办公室官网“中国民用航空安全信息系统”公布9起民航事件调查报告。华商报大风新闻记者注意到，其中多次事件，此前曾引发关注。      根据网站“调查报告”栏目显示....', '2026-03-31T11:03:57.819Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5939, 'tencent-hot', '俄罗斯拒绝向日本供油：当前能源短缺且价格上涨，日本政府仍受限于对俄罗斯石油设定价格上限，俄将不会向支持石油价格上限的国家供应石油', 'https://view.inews.qq.com/a/20260331A044BA00', '0', 159, '', '据俄新社3月31日报道，俄罗斯外交部副部长安德烈·鲁登科向俄罗斯《消息报》表示，俄罗斯将不会向支持石油价格上限的国家供应石油。报道称，鲁登科说：“当前能源市场局势波动剧烈，能源出现短缺且价格持续上涨，但日本政府仍受限于对俄罗斯石油设定价格上限的相关义务，这一措施违背市场规律，破坏供应链。俄方已多次声明...', '2026-03-31T19:03:54.610Z');
