INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6749, 'baidu-hot', '老凤祥换新 4.66克金饰换回2.71克', 'https://www.baidu.com/s?wd=%E8%80%81%E5%87%A4%E7%A5%A5%E6%8D%A2%E6%96%B0+4.66%E5%85%8B%E9%87%91%E9%A5%B0%E6%8D%A2%E5%9B%9E2.71%E5%85%8B&sa=fyb_news&rsv_dl=fyb_news', '4564621', 124, '', '近日，求女士在老凤祥银楼办理黄金以旧换新，4.66克旧金仅换得2.71克新项链。求女士认为商家误导消费，门店则称全程按照规定操作。经协调，门店提出按照旧金总重为求女士重新办理按克换克置换。但该方案被求女士拒绝，她表示将通过司法途径维权。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5384, 'baidu-hot', '中方三艘船舶过航霍尔木兹海峡', 'https://www.baidu.com/s?wd=%E4%B8%AD%E6%96%B9%E4%B8%89%E8%89%98%E8%88%B9%E8%88%B6%E8%BF%87%E8%88%AA%E9%9C%8D%E5%B0%94%E6%9C%A8%E5%85%B9%E6%B5%B7%E5%B3%A1&sa=fyb_news&rsv_dl=fyb_news', '3122578', 262, '', '3月31日，外交部发言人毛宁在例行记者会上称，经同有关方面协调，近日中方有三艘船舶过航霍尔木兹海峡，我们对有关方面提供的协助表示感谢。中方呼吁尽快停火止战，恢复海湾地区和平稳定。', '2026-03-31T11:03:49.605Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6752, 'baidu-hot', '国台办回应台隐蔽战线牺牲者骨灰回陆', 'https://www.baidu.com/s?wd=%E5%9B%BD%E5%8F%B0%E5%8A%9E%E5%9B%9E%E5%BA%94%E5%8F%B0%E9%9A%90%E8%94%BD%E6%88%98%E7%BA%BF%E7%89%BA%E7%89%B2%E8%80%85%E9%AA%A8%E7%81%B0%E5%9B%9E%E9%99%86&sa=fyb_news&rsv_dl=fyb_news', '3105117', 266, '', '4月1日，国台办发言人张晗在例行发布会上回应“多位台湾隐蔽战线牺牲者骨灰清明节前归葬大陆”，强调清明节是慎终追远的传统节日，人民和历史不会遗忘先烈，其精神将激励两岸同胞推进统一事业。', '2026-03-31T22:03:39.330Z');
