INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6656, 'baidu-hot', '王伟牺牲25年 妻子：这盛世如你所愿', 'https://www.baidu.com/s?wd=%E7%8E%8B%E4%BC%9F%E7%89%BA%E7%89%B225%E5%B9%B4+%E5%A6%BB%E5%AD%90%EF%BC%9A%E8%BF%99%E7%9B%9B%E4%B8%96%E5%A6%82%E4%BD%A0%E6%89%80%E6%84%BF&sa=fyb_news&rsv_dl=fyb_news', '5521516', 81, '', '25年前的4月1日，海军航空兵飞行员王伟在南海拦截美军侦察机时壮烈牺牲，终年33岁。近日，妻子阮国琴深情表示：“当年你总说，咱们的飞机落后，如今，咱们的歼-20已经翱翔蓝天、山东舰的甲板上停满了‘飞鲨’……阿伟，你看到了吗？这盛世如你所愿。”', '2026-03-31T23:05:26.297Z');
