INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5414, 'baidu-hot', '宝妈创业一天卖700个创意馒头', 'https://www.baidu.com/s?wd=%E5%AE%9D%E5%A6%88%E5%88%9B%E4%B8%9A%E4%B8%80%E5%A4%A9%E5%8D%96700%E4%B8%AA%E5%88%9B%E6%84%8F%E9%A6%92%E5%A4%B4&sa=fyb_news&rsv_dl=fyb_news', '3886802', 169, '', '近日，湖北一“95后”宝妈的馒头店火了。据悉，其创业一天可以卖六七百个，从摆摊实现开店。店主表示：“将近有80个品种、均价4元。线上群有1200人，主要靠回头客，复购可以派送到家。”', '2026-03-31T02:04:09.664Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6416, 'baidu-hot', '俄罗斯一架运输机坠毁 29人遇难', 'https://www.baidu.com/s?wd=%E4%BF%84%E7%BD%97%E6%96%AF%E4%B8%80%E6%9E%B6%E8%BF%90%E8%BE%93%E6%9C%BA%E5%9D%A0%E6%AF%81+29%E4%BA%BA%E9%81%87%E9%9A%BE&sa=fyb_news&rsv_dl=fyb_news', '5504937', 85, '', '据4月1日俄罗斯国防部消息，俄罗斯一架安-26型运输机在克里米亚地区因技术故障坠毁，6名机组人员和23名乘客全部遇难。', '2026-03-31T21:04:36.021Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6579, 'baidu-hot', '高铁车厢变蚊窝？列车员：未关窗导致', 'https://www.baidu.com/s?wd=%E9%AB%98%E9%93%81%E8%BD%A6%E5%8E%A2%E5%8F%98%E8%9A%8A%E7%AA%9D%EF%BC%9F%E5%88%97%E8%BD%A6%E5%91%98%EF%BC%9A%E6%9C%AA%E5%85%B3%E7%AA%97%E5%AF%BC%E8%87%B4&sa=fyb_news&rsv_dl=fyb_news', '4066866', 158, '', '3月31日，多名网友发帖称，当天下午从香港西九龙发车的G386次高铁列车车厢内出现大量蚊虫，严重影响出行。还有网友透露对于蚊虫涌入车厢的原因，列车员曾解释称，系前一日停在潮汕检修，当晚开了一整晚车窗导致。', '2026-03-31T19:04:12.827Z');
