INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5612, 'tencent-hot', '实探两轮电动车门店：未接涨价通知，有店员称“轮胎等都跟着石油涨”', 'https://view.inews.qq.com/a/20260331A04AWT00', '0', 136, '', '中新经纬3月31日电 (周奕航)继冲锋衣、内衣、卫生巾之后，两轮电动车也要涨价了？ 近日，关于“两轮电动车价格即将上调”的讨论引起关注。3月30日，中新经纬以消费者身份，实地走访了北京市西城区的雅迪、爱玛、小牛、九号等5家电动自行车门店。多家门店店员表示，现在还没接到明确的涨价消息，但4月份电动车价格可能会上调...', '2026-03-31T15:03:48.515Z');
