INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5207, 'tencent-hot', '美客机与黑鹰直升机相撞画面曝光：相撞前，客机尝试爬升但为时已晚，瞬间出现爆炸火球，事故造成67人死亡，美国政府承认对事故负有责任', 'https://view.inews.qq.com/a/20260330A07F1U00', '0', 72, '', '3月30日，美国哥伦比亚广播公司在一档节目中披露了一段2025年1月美国航空公司一架客机与一架美国陆军“黑鹰”直升机相撞事故的视频。画面显示，在相撞前，客机尝试爬升但为时已晚。据报道，该事故造成67人死亡，美国政府承认对事故负有责任。————————————来 源：参考消息编 辑：宋聪俐校 对：郑 瑾值班主任：钟...', '2026-03-31T02:03:51.981Z');
