INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6495, 'baidu-hot', '多所高校宣布2026年本科扩招', 'https://www.baidu.com/s?wd=%E5%A4%9A%E6%89%80%E9%AB%98%E6%A0%A1%E5%AE%A3%E5%B8%832026%E5%B9%B4%E6%9C%AC%E7%A7%91%E6%89%A9%E6%8B%9B&sa=fyb_news&rsv_dl=fyb_news', '4652493', 121, '', '近期多所高校公布了今年的本科招生计划，其中新型研究型大学扩大招生规模受到关注。南方科技大学、大湾区大学及深圳理工大学等多所高校披露将扩大招生规模。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5947, 'baidu-hot', '可载重3.5吨的“无人空中重卡”来了', 'https://www.baidu.com/s?wd=%E5%8F%AF%E8%BD%BD%E9%87%8D3.5%E5%90%A8%E7%9A%84%E2%80%9C%E6%97%A0%E4%BA%BA%E7%A9%BA%E4%B8%AD%E9%87%8D%E5%8D%A1%E2%80%9D%E6%9D%A5%E4%BA%86&sa=fyb_news&rsv_dl=fyb_news', '7618500', 7, '', '3月31日，长鹰-8（NORINCO LUCA）大型运投无人机在郑州上街机场首飞成功，成为全球迄今首飞的最大货运无人机。长鹰-8被誉为“无人空中重卡”，最大载货重量达到3.5吨。', '2026-03-31T18:04:27.648Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6412, 'baidu-hot', '辽宁舰山东舰福建舰呼叫', 'https://www.baidu.com/s?wd=%E8%BE%BD%E5%AE%81%E8%88%B0%E5%B1%B1%E4%B8%9C%E8%88%B0%E7%A6%8F%E5%BB%BA%E8%88%B0%E5%91%BC%E5%8F%AB&sa=fyb_news&rsv_dl=fyb_news', '3621713', 194, '', '“这里是中国海军辽宁舰、中国海军山东舰、中国海军福建舰，甲板已清空、空域已清空、防空识别已开启，可以降落，请立即返航！”“81192收到！”4月1日，是“海空卫士”王伟牺牲25周年。2001年，他为保卫祖国领空遭美机撞机被迫跳伞坠海牺牲，年仅33岁。', '2026-03-31T21:04:36.021Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5401, 'baidu-hot', '午睡超过这个时间 真的会越睡越累', 'https://www.baidu.com/s?wd=%E5%8D%88%E7%9D%A1%E8%B6%85%E8%BF%87%E8%BF%99%E4%B8%AA%E6%97%B6%E9%97%B4+%E7%9C%9F%E7%9A%84%E4%BC%9A%E8%B6%8A%E7%9D%A1%E8%B6%8A%E7%B4%AF&sa=fyb_news&rsv_dl=fyb_news', '5695194', 75, '', '午睡的最佳时长为20至30分钟。若超过30分钟，人体易进入深度睡眠，醒来后可能出现头昏脑涨、反应迟钝的“睡眠惯性”，反而越睡越累。建议饭后消化20-30分钟后再午睡，效果最佳。​​​​', '2026-03-31T00:24:20.878Z');
