INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5392, 'baidu-hot', '年轻人开始尝试“吊颈健身”', 'https://www.baidu.com/s?wd=%E5%B9%B4%E8%BD%BB%E4%BA%BA%E5%BC%80%E5%A7%8B%E5%B0%9D%E8%AF%95%E2%80%9C%E5%90%8A%E9%A2%88%E5%81%A5%E8%BA%AB%E2%80%9D&sa=fyb_news&rsv_dl=fyb_news', '7523272', 11, '', '“吊颈健身”近期在年轻人中走红，但其模仿的颈椎牵引与正规医疗操作天壤之别。医生提醒，正规牵引需在专业指导下精确控制角度、重量和时间，而“吊颈健身”将全身重量挂在脖子上，极易导致颈椎错位或骨折。与其冒险，不如从调整姿势、减少低头、热敷按摩及选对枕头等日常习惯入手保护颈椎。​​​​', '2026-03-31T02:04:09.664Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5773, 'baidu-hot', '印度将启动全世界最大规模人口普查', 'https://www.baidu.com/s?wd=%E5%8D%B0%E5%BA%A6%E5%B0%86%E5%90%AF%E5%8A%A8%E5%85%A8%E4%B8%96%E7%95%8C%E6%9C%80%E5%A4%A7%E8%A7%84%E6%A8%A1%E4%BA%BA%E5%8F%A3%E6%99%AE%E6%9F%A5&sa=fyb_news&rsv_dl=fyb_news', '4458379', 131, '', '3月30日，印度政府宣布，原定于2021年举行的全国人口普查将于今年4月1日正式开始。本次人口普查将是印度在1931年后首次进行完整的种姓普查，也将是世界上最大规模的人口普查。', '2026-03-31T15:04:07.795Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5769, 'baidu-hot', '丝芭传媒否认举报鞠婧祎偷税漏税', 'https://www.baidu.com/s?wd=%E4%B8%9D%E8%8A%AD%E4%BC%A0%E5%AA%92%E5%90%A6%E8%AE%A4%E4%B8%BE%E6%8A%A5%E9%9E%A0%E5%A9%A7%E7%A5%8E%E5%81%B7%E7%A8%8E%E6%BC%8F%E7%A8%8E&sa=fyb_news&rsv_dl=fyb_news', '4166588', 148, '', '3月31日，丝芭传媒发文否认举报鞠婧祎：我司并非举报主体，任何操控将祸水引向我司的作秀，其根本目的是模糊焦点，混淆视听。依法纳税是每一位公民应尽的义务，艺人更应积极自审自查，接受舆论的监督。', '2026-03-31T15:04:07.795Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5862, 'baidu-hot', '业内人士回应内存产品价格大跳水', 'https://www.baidu.com/s?wd=%E4%B8%9A%E5%86%85%E4%BA%BA%E5%A3%AB%E5%9B%9E%E5%BA%94%E5%86%85%E5%AD%98%E4%BA%A7%E5%93%81%E4%BB%B7%E6%A0%BC%E5%A4%A7%E8%B7%B3%E6%B0%B4&sa=fyb_news&rsv_dl=fyb_news', '3872911', 174, '', '近日，“内存条价格断崖式下跌”冲上热搜第一，多位存储行业的供应链人士称，从零售、现货市场甚至到整个产业链，存储产品的供货依然是“老大难”问题。存储模组厂商江波龙的一高管表示，此次“跳水”更像是一场被放大的短期波动。', '2026-03-31T15:04:07.795Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5772, 'baidu-hot', '张雪从请采访我到请接受采访', 'https://www.baidu.com/s?wd=%E5%BC%A0%E9%9B%AA%E4%BB%8E%E8%AF%B7%E9%87%87%E8%AE%BF%E6%88%91%E5%88%B0%E8%AF%B7%E6%8E%A5%E5%8F%97%E9%87%87%E8%AE%BF&sa=fyb_news&rsv_dl=fyb_news', '3499297', 210, '', '张雪接受采访时的这个细节你注意到了吗？2006年，张雪看到记者时求着记者采访自己，而20年后，张雪被大量记者包围采访。从“请采访我”到“请接受采访” 如今的他衣服上挂满了采访话筒。', '2026-03-31T15:04:07.795Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6283, 'baidu-hot', '王楚钦回应开门红：打之前很忐忑', 'https://www.baidu.com/s?wd=%E7%8E%8B%E6%A5%9A%E9%92%A6%E5%9B%9E%E5%BA%94%E5%BC%80%E9%97%A8%E7%BA%A2%EF%BC%9A%E6%89%93%E4%B9%8B%E5%89%8D%E5%BE%88%E5%BF%90%E5%BF%91&sa=fyb_news&rsv_dl=fyb_news', '3204329', 255, '', '3月31日，2026年国际乒联单打世界杯小组赛继续进行。王楚钦3-0横扫罗马尼亚选手约内斯库，取得了本届世界杯开门红。‌‌王楚钦赛后接受采访时表示：没打之前很忐忑，但是第一场能发挥成这样，自己非常满意。', '2026-03-31T15:04:07.795Z');
