INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5423, 'baidu-hot', '外国小伙误入喜丧现场“蹭饭”', 'https://www.baidu.com/s?wd=%E5%A4%96%E5%9B%BD%E5%B0%8F%E4%BC%99%E8%AF%AF%E5%85%A5%E5%96%9C%E4%B8%A7%E7%8E%B0%E5%9C%BA%E2%80%9C%E8%B9%AD%E9%A5%AD%E2%80%9D&sa=fyb_news&rsv_dl=fyb_news', '3586956', 200, '', '近日，美国网红Ludwig（路德维希）和同伴麦克的一段中国摩旅视频，在外网掀起了一阵讨论热潮。视频里，两个金发碧眼的外国人误将湖南农村的喜丧酒席认作网红餐厅，用蹩脚中文问出“可以吃吗”，一位大哥用英文夹中文的方式和他们全程交流，让无数网友忍俊不禁。', '2026-03-31T00:24:20.878Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5394, 'baidu-hot', '“每10股”写成“每股” 交行致歉', 'https://www.baidu.com/s?wd=%E2%80%9C%E6%AF%8F10%E8%82%A1%E2%80%9D%E5%86%99%E6%88%90%E2%80%9C%E6%AF%8F%E8%82%A1%E2%80%9D+%E4%BA%A4%E8%A1%8C%E8%87%B4%E6%AD%89&sa=fyb_news&rsv_dl=fyb_news', '4943275', 106, '', '3月30日，交通银行针对此前披露的文件发布更正公告并致歉。更正前，交通银行2025年度全年每股分配现金股利3.247元（含税）；更正后的方案为2025年度全年每10股分配现金股利3.247元（含税），仅一字之差，二者差额高达约2582亿元。', '2026-03-31T04:04:06.774Z');
