INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5412, 'baidu-hot', '5岁男孩患病从小瘫痪突然站立', 'https://www.baidu.com/s?wd=5%E5%B2%81%E7%94%B7%E5%AD%A9%E6%82%A3%E7%97%85%E4%BB%8E%E5%B0%8F%E7%98%AB%E7%97%AA%E7%AA%81%E7%84%B6%E7%AB%99%E7%AB%8B&sa=fyb_news&rsv_dl=fyb_news', '3679172', 191, '', '3月30日，安徽合肥一名患罕见病的5岁男孩突然自主站立行走，母亲杨女士看到孩子迈出第一步时表示：“这些年的努力没有白费”，尽管行走尚不稳定，但五年的康复治疗终见成效。', '2026-03-31T18:04:27.648Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6821, 'baidu-hot', 'Colorwalk怎么火了', 'https://www.baidu.com/s?wd=Colorwalk%E6%80%8E%E4%B9%88%E7%81%AB%E4%BA%86&sa=fyb_news&rsv_dl=fyb_news', '6179359', 58, '', '出门前选定一种颜色，以此为线索漫步街头，寻找一切与该颜色相关的事物，拍下照片，组合成一篇色彩日记——今年春天，这种名为“Colorwalk”（色彩漫步）的玩法在社交平台上兴起。如此简单的玩法能够“破圈”，不仅在于参与门槛较低，更深层的原因还在于它所提供的情绪价值。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6819, 'baidu-hot', '浙创投为张雪机车投资9000万', 'https://www.baidu.com/s?wd=%E6%B5%99%E5%88%9B%E6%8A%95%E4%B8%BA%E5%BC%A0%E9%9B%AA%E6%9C%BA%E8%BD%A6%E6%8A%95%E8%B5%849000%E4%B8%87&sa=fyb_news&rsv_dl=fyb_news', '5421179', 86, '', '近日，在世界超级摩托车锦标赛葡萄牙站WorldSSP组别夺冠后，“张雪机车”热度持续攀升，相关概念股应声涨停，而浙江资本以9000万元“突击入股”的提前布局也引发业内关注。据投资方介绍，多年前张雪闭眼装发动机，打动了投资人。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6817, 'baidu-hot', '李荣浩否认抄袭', 'https://www.baidu.com/s?wd=%E6%9D%8E%E8%8D%A3%E6%B5%A9%E5%90%A6%E8%AE%A4%E6%8A%84%E8%A2%AD&sa=fyb_news&rsv_dl=fyb_news', '5218758', 95, '', '4月1日，李荣浩发文回应抄袭风波：首先我要说，我没有抄袭。在歌曲《小眼睛》的问题上，我认为已经超越抄袭。这就是那首歌原曲，换了位歌手唱了一遍。这件事一定会有结果，大家等我消息。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6422, 'baidu-hot', '年轻人开始去门诊“查心”', 'https://www.baidu.com/s?wd=%E5%B9%B4%E8%BD%BB%E4%BA%BA%E5%BC%80%E5%A7%8B%E5%8E%BB%E9%97%A8%E8%AF%8A%E2%80%9C%E6%9F%A5%E5%BF%83%E2%80%9D&sa=fyb_news&rsv_dl=fyb_news', '3394478', 226, '', '近期，越来越多的年轻人开始去门诊“查心”。对此，专家表示，对普通人来说，思考要不要去医院做检查时，可以先做一些简单的自我筛查。如发现具有较多高血脂、肥胖、运动后胸闷等危险因素，应当考虑就诊。如果没有，又相当年轻，不需要太害怕。', '2026-03-31T18:04:27.648Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5936, 'tencent-hot', '贺光辉同志逝世', 'https://view.inews.qq.com/a/20260331A07E4Z00', '0', 188, '', '新华社北京3月31日电 原国家经济体制改革委员会党组书记、副主任贺光辉同志（正部长级），因病于2026年3月22日在北京逝世，享年97岁。 贺光辉同志逝世后，中央有关领导同志以不同方式表示哀悼并向其亲属表示慰问。 贺光辉，1929年1月生，陕西清涧人。1942年12月参加革命工作，1945年11月加入中国共产党。1947年至1950年先后...', '2026-03-31T23:24:36.401Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6424, 'baidu-hot', '男子殴打女友 法院：同居暴力是家暴', 'https://www.baidu.com/s?wd=%E7%94%B7%E5%AD%90%E6%AE%B4%E6%89%93%E5%A5%B3%E5%8F%8B+%E6%B3%95%E9%99%A2%EF%BC%9A%E5%90%8C%E5%B1%85%E6%9A%B4%E5%8A%9B%E6%98%AF%E5%AE%B6%E6%9A%B4&sa=fyb_news&rsv_dl=fyb_news', '4088939', 154, '', '3月30日，北京市第三中级人民法院通报一起案例：何某在与女友陈某同居期间，因感情问题对陈某实施殴打，致其重伤二级、八级伤残。法院认定何某的暴力行为严重侵害妇女权益，判决何某犯故意伤害罪，判处有期徒刑五年六个月。', '2026-03-31T16:04:21.744Z');
