INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6393, 'tencent-hot', '视频丨呼叫81192，甲板已清空，等你返航！', 'https://view.inews.qq.com/a/20260401A019V200', '2474457', 3, '', '25年前的4月1日为守护祖国海空“海空卫士”王伟壮烈牺牲英雄从未远去 我们不曾忘记今天，我们再次呼唤“81192，请返航” 25年前的那一天他为守护海空壮烈牺牲2001年美国一架侦察机侵犯我南海领空飞行员王伟奉命执行跟踪监视任务美机违反飞行规则突然转向将王伟驾驶的飞机撞毁王伟被迫跳伞坠海军民出动搜救人员10余万人次海军出动舰艇13艘次飞机115架次在8万多平方公里的范围内反复搜寻都没有找到他的踪迹……中央军委追授王伟同志“海空卫士”荣誉称号和一级英模奖章 中国航母驶向深蓝这些好消息多希望你能看到！王伟生前曾经手绘油画《夙愿》画中一名飞行员驾驶舰载机从航母上起飞△王伟生前手绘油画《夙愿》2012...', '2026-04-01T01:45:29.761Z');
