INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7006, 'baidu-hot', '张雪机车为何不允许新手购买', 'https://www.baidu.com/s?wd=%E5%BC%A0%E9%9B%AA%E6%9C%BA%E8%BD%A6%E4%B8%BA%E4%BD%95%E4%B8%8D%E5%85%81%E8%AE%B8%E6%96%B0%E6%89%8B%E8%B4%AD%E4%B9%B0&sa=fyb_news&rsv_dl=fyb_news', '6661830', 44, '', '当地时间3月29日，张雪机车在世界超级摩托车锦标赛葡萄牙站夺冠后，创始人张雪推出新规：禁止驾龄不满一年的“新手”购买旗下新款大排量车型，还设立举报奖励机制，举报核实可获5000元，他称此举为保障用户安全。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6418, 'baidu-hot', '用户投诉移动“流量安全阀”不安全', 'https://www.baidu.com/s?wd=%E7%94%A8%E6%88%B7%E6%8A%95%E8%AF%89%E7%A7%BB%E5%8A%A8%E2%80%9C%E6%B5%81%E9%87%8F%E5%AE%89%E5%85%A8%E9%98%80%E2%80%9D%E4%B8%8D%E5%AE%89%E5%85%A8&sa=fyb_news&rsv_dl=fyb_news', '3580509', 203, '', '近日，林先生订购了移动“流量安全阀”业务，结果2月套餐流量没用完，就被停止使用流量。3月套餐流量用超了，安全阀也没启用。“已经订购的业务出问题不修复，反而悄悄改规则，移动的做法太不合理。”林先生说。', '2026-03-31T19:04:12.827Z');
