INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5771, 'baidu-hot', '在户外头发突然竖起怎么办', 'https://www.baidu.com/s?wd=%E5%9C%A8%E6%88%B7%E5%A4%96%E5%A4%B4%E5%8F%91%E7%AA%81%E7%84%B6%E7%AB%96%E8%B5%B7%E6%80%8E%E4%B9%88%E5%8A%9E&sa=fyb_news&rsv_dl=fyb_news', '5139338', 96, '', '在户外头发突然竖起怎么办？专家：它的原理是头顶上的云带电了，很有可能会发生闪电。这时应该就地找一个比较低的地方，双脚并拢蹲下去。', '2026-03-31T05:04:26.574Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6166, 'baidu-hot', '伊朗称打击以色列境内科技公司', 'https://www.baidu.com/s?wd=%E4%BC%8A%E6%9C%97%E7%A7%B0%E6%89%93%E5%87%BB%E4%BB%A5%E8%89%B2%E5%88%97%E5%A2%83%E5%86%85%E7%A7%91%E6%8A%80%E5%85%AC%E5%8F%B8&sa=fyb_news&rsv_dl=fyb_news', '4351192', 138, '', '当地时间3月31日，伊朗军队发布声明称，为回应以色列和美国对伊朗基础设施的袭击，自当天凌晨起，伊朗出动攻击型无人机，打击了位于以色列本-古里安国际机场和海法地区的西门子公司、美国电话电报公司的通讯、电信与工业中心。', '2026-03-31T17:04:28.395Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7012, 'baidu-hot', '300元1次的宠物健身先把狗卷疯了', 'https://www.baidu.com/s?wd=300%E5%85%831%E6%AC%A1%E7%9A%84%E5%AE%A0%E7%89%A9%E5%81%A5%E8%BA%AB%E5%85%88%E6%8A%8A%E7%8B%97%E5%8D%B7%E7%96%AF%E4%BA%86&sa=fyb_news&rsv_dl=fyb_news', '3104264', 268, '', '“2000元一个月的宠物健身房！你会去吗？”一位网友在社交平台发出这个疑问后，立刻引发了广泛讨论。有网友表示：“我还没练出腹肌，300元/次的宠物健身先把狗卷疯了。”', '2026-03-31T23:05:26.297Z');
