INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5617, 'baidu-hot', '哈尔滨41岁女企业家朱明月离世', 'https://www.baidu.com/s?wd=%E5%93%88%E5%B0%94%E6%BB%A841%E5%B2%81%E5%A5%B3%E4%BC%81%E4%B8%9A%E5%AE%B6%E6%9C%B1%E6%98%8E%E6%9C%88%E7%A6%BB%E4%B8%96&sa=fyb_news&rsv_dl=fyb_news', '4542174', 128, '', '3月30日，芈朵账号发文，表示账号主人朱明月于3月26日因病医治无效去世，年仅41岁。据悉，朱明月担任多家企业法定代表人、股东及高管等职务，并控股相关企业。2018年，获评创新中国（行业）十大榜样人物。', '2026-03-31T07:04:28.019Z');
