INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6748, 'baidu-hot', '台湾掀起“抢塑潮” 国台办回应', 'https://www.baidu.com/s?wd=%E5%8F%B0%E6%B9%BE%E6%8E%80%E8%B5%B7%E2%80%9C%E6%8A%A2%E5%A1%91%E6%BD%AE%E2%80%9D+%E5%9B%BD%E5%8F%B0%E5%8A%9E%E5%9B%9E%E5%BA%94&sa=fyb_news&rsv_dl=fyb_news', '7809302', 1, '', '4月1日，国台办发言人张晗回应“台湾近期因中东战事掀起的‘抢塑潮’”。她表示，和平统一后，两岸实现互联互通、应通尽通。无论外部形势如何动荡不安，都可以为台湾的能源资源安全、工业生产物资供给提供及时保障，台湾同胞再也无需为各种能源、物资短缺而焦虑。', '2026-03-31T23:05:26.297Z');
