INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5938, 'tencent-hot', '张雪机车上的“麻阳古法红糖”火了！村支书称村里红糖已卖完，有网店一天卖了近300单', 'https://view.inews.qq.com/a/20260331A043OQ00', '0', 84, '', '“张雪机车”夺冠后，贴在车上的“麻阳古法红糖”也火了。3月31日，张雪的老乡张先生告诉红星新闻，3月30日，他朋友网店上销售的麻阳红糖，当天直接销售了近300单。老乡张先生介绍，春节前，张雪和团队到他家吃饭后，问了村里的红糖销售情况，得知不理想，便将“麻阳古法红糖”几个字贴在机车上，免费代言。同时，湖南怀化...', '2026-03-31T05:03:51.879Z');
