INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6498, 'baidu-hot', '军事机密泄露竟是因为运动手表', 'https://www.baidu.com/s?wd=%E5%86%9B%E4%BA%8B%E6%9C%BA%E5%AF%86%E6%B3%84%E9%9C%B2%E7%AB%9F%E6%98%AF%E5%9B%A0%E4%B8%BA%E8%BF%90%E5%8A%A8%E6%89%8B%E8%A1%A8&sa=fyb_news&rsv_dl=fyb_news', '7141027', 26, '', '近日，某国一起军事机密泄露事件，引发全球关注。当时该国某重要军事装备正在执行任务，一名军官跑步时佩戴的智能运动手表持续记录并公开了高精度GPS数据，致使该装备的重要敏感信息泄露，给该国国防安全造成难以弥补的重大损失。', '2026-03-31T23:05:26.297Z');
