INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6557, '36kr-hot', '延迟刊发2025年业绩，Mirxes-B回应：与公司研发等没有直接关系，日常运营正常', '<![CDATA[https://36kr.com/newsflashes/3747614173971201?f=rss]]>', '0', 90, '', '4月1日，港股Mirxes-B公告，公司将延迟刊发2025年年度业绩报告。受此影响，该公司股份已于今日（4月1日）上午9时起在联交所暂停买卖。Mirxes-B相关负责人回应称，公告详细披露了目前核数师', '2026-03-31T18:04:04.521Z');
