INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6487, '36kr-hot', '黄金ETF规模缩水，短期震荡不改长期走势', '<![CDATA[https://36kr.com/newsflashes/3747521093255939?f=rss]]>', '0', 80, '', '3月下旬以来，黄金市场结束前期单边上行走势，转入大幅震荡阶段，相关黄金ETF的资金面也有所转弱，多只黄金ETF最近一周规模缩水超30亿元。黄金市场为何短期面临大幅震荡？长期逻辑是否发生变化？在机构人士', '2026-03-31T17:04:06.989Z');
