INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7129, 'tencent-hot', '中东战火，烧到了汽车', 'https://view.inews.qq.com/a/20260401A04HXB00', '1780205', 22, '', '“中东冲突正在使汽车工业脱轨。”《福布斯》杂志近日发表的一篇分析称，对汽车行业而言，这场冲突堪称一场“灾难”。其中，铝正是冲突的最新受害者。伊朗伊斯兰革命卫队3月29日发表声明称，革命卫队用导弹和无人机打击了阿联酋和巴林境内与美国军事和航空航天业有关的两家铝厂。随之，阿联酋环球铝业、巴林铝业、卡塔尔铝...', '2026-04-01T01:45:29.761Z');
