INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6961, '36kr-hot', '越南VinFast将实现盈亏平衡时间推迟至2027年之后', '<![CDATA[https://36kr.com/newsflashes/3747892912456201?f=rss]]>', '0', 146, '', '据两位知情人士透露，越南电动汽车制造商VinFast目前预计，由于该公司正积极推进快速扩张计划，同时还要应对不断上涨的成本，因此要到2027年之后才能实现盈亏平衡。（新浪财经）', '2026-03-31T23:24:35.263Z');
