INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6753, 'baidu-hot', '因没消费 游客景区拍照遭商家抢手机', 'https://www.baidu.com/s?wd=%E5%9B%A0%E6%B2%A1%E6%B6%88%E8%B4%B9+%E6%B8%B8%E5%AE%A2%E6%99%AF%E5%8C%BA%E6%8B%8D%E7%85%A7%E9%81%AD%E5%95%86%E5%AE%B6%E6%8A%A2%E6%89%8B%E6%9C%BA&sa=fyb_news&rsv_dl=fyb_news', '3403868', 224, '', '近日，有游客称在同里古镇拍照时，因未进行消费遭商家驱赶抢手机。报警后，对方赔偿200元医药费。4月1日，苏州同里镇政府通报表示：已责成涉事商户停业整改，对此深表歉意。', '2026-03-31T22:40:49.014Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6867, 'baidu-hot', '纽约撤销政府设备使用TikTok禁令', 'https://www.baidu.com/s?wd=%E7%BA%BD%E7%BA%A6%E6%92%A4%E9%94%80%E6%94%BF%E5%BA%9C%E8%AE%BE%E5%A4%87%E4%BD%BF%E7%94%A8TikTok%E7%A6%81%E4%BB%A4&sa=fyb_news&rsv_dl=fyb_news', '3115032', 263, '', '美国纽约市长祖赫兰·马姆达尼3月31日宣布，决定允许在政府电子设备上恢复使用短视频社交媒体平台TikTok。当天，马姆达尼在该社交媒体平台上发布消息说：“TikTok，我们回来了。”', '2026-03-31T22:40:49.014Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6661, 'baidu-hot', '“未缴车位费不抬杆”属违法催缴', 'https://www.baidu.com/s?wd=%E2%80%9C%E6%9C%AA%E7%BC%B4%E8%BD%A6%E4%BD%8D%E8%B4%B9%E4%B8%8D%E6%8A%AC%E6%9D%86%E2%80%9D%E5%B1%9E%E8%BF%9D%E6%B3%95%E5%82%AC%E7%BC%B4&sa=fyb_news&rsv_dl=fyb_news', '6081950', 63, '', '近日，成都一小区物业设置的道闸系统，对未缴纳车位管理费的业主不予识别，需人工操作抬杆放行。律师：物业服务人以限制门禁系统使用等方式催交物业费，属不当限制业主建筑物区分所有权的违法行为。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6168, 'baidu-hot', '网友称才三月就被蚊子叮到睡不着', 'https://www.baidu.com/s?wd=%E7%BD%91%E5%8F%8B%E7%A7%B0%E6%89%8D%E4%B8%89%E6%9C%88%E5%B0%B1%E8%A2%AB%E8%9A%8A%E5%AD%90%E5%8F%AE%E5%88%B0%E7%9D%A1%E4%B8%8D%E7%9D%80&sa=fyb_news&rsv_dl=fyb_news', '3413988', 222, '', '近日，全国多地的网友表示，才三月就被蚊子叮得睡不着，话题“今年蚊子可能迎来史诗级加强”登上热搜，专家称今年气温偏高有利于蚊虫繁殖。3月27日，中疾控发文提醒预防蚊虫叮咬。', '2026-03-31T15:04:07.795Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6864, 'baidu-hot', '中国最强“东西大动脉”要来了', 'https://www.baidu.com/s?wd=%E4%B8%AD%E5%9B%BD%E6%9C%80%E5%BC%BA%E2%80%9C%E4%B8%9C%E8%A5%BF%E5%A4%A7%E5%8A%A8%E8%84%89%E2%80%9D%E8%A6%81%E6%9D%A5%E4%BA%86&sa=fyb_news&rsv_dl=fyb_news', '7713466', 5, '', '长江入海口崇太长江隧道14公里江底段施工完成，标志着沿江高铁（沪渝蓉高铁）建设取得关键进展。这条5000亿的东西大动脉，将带动1.5万亿经济增长，重塑长江经济带格局。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6652, 'baidu-hot', '旅游新规落地 将带来哪些新变化', 'https://www.baidu.com/s?wd=%E6%97%85%E6%B8%B8%E6%96%B0%E8%A7%84%E8%90%BD%E5%9C%B0+%E5%B0%86%E5%B8%A6%E6%9D%A5%E5%93%AA%E4%BA%9B%E6%96%B0%E5%8F%98%E5%8C%96&sa=fyb_news&rsv_dl=fyb_news', '7617958', 8, '', '新版《旅游规划通则》4月1日起实施。景区客流调控更准，游览节奏更从容；地方特色得到挖掘，每站各有韵味；标识导览等标准清晰，出行体验更顺心。游客意见也可参与规划，让每次出发都有新的遇见。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6581, 'baidu-hot', '家庭主妇离婚获5万家务补偿', 'https://www.baidu.com/s?wd=%E5%AE%B6%E5%BA%AD%E4%B8%BB%E5%A6%87%E7%A6%BB%E5%A9%9A%E8%8E%B75%E4%B8%87%E5%AE%B6%E5%8A%A1%E8%A1%A5%E5%81%BF&sa=fyb_news&rsv_dl=fyb_news', '3229838', 245, '', '近日，有媒体获悉一起案例，彭某（男）与刘某（女）结婚多年，刘某为抚育子女、照料家庭长期无业，离婚时要求按市价获赔保姆级家务补偿，最终判决彭某支付刘某5万元家务劳动补偿。', '2026-03-31T20:04:10.909Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6754, 'baidu-hot', '和平统一后台胞无需为能源短缺焦虑', 'https://www.baidu.com/s?wd=%E5%92%8C%E5%B9%B3%E7%BB%9F%E4%B8%80%E5%90%8E%E5%8F%B0%E8%83%9E%E6%97%A0%E9%9C%80%E4%B8%BA%E8%83%BD%E6%BA%90%E7%9F%AD%E7%BC%BA%E7%84%A6%E8%99%91&sa=fyb_news&rsv_dl=fyb_news', '3148624', 256, '', '4月1日，国台办发言人张晗在例行发布会上回应台湾能源短缺问题时表示，和平统一后，两岸实现互联互通、应通尽通，大陆完整的产业体系和稳定的市场供应能力，完全可以弥补台湾在原油、天然气、工业原料等方面的短缺。无论外部形势如何动荡不安，台湾同胞也无需为各种能源物资短缺而焦虑。', '2026-03-31T20:04:10.909Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5409, 'baidu-hot', '被曝用年轻人血液换血治疗？企业声明', 'https://www.baidu.com/s?wd=%E8%A2%AB%E6%9B%9D%E7%94%A8%E5%B9%B4%E8%BD%BB%E4%BA%BA%E8%A1%80%E6%B6%B2%E6%8D%A2%E8%A1%80%E6%B2%BB%E7%96%97%EF%BC%9F%E4%BC%81%E4%B8%9A%E5%A3%B0%E6%98%8E&sa=fyb_news&rsv_dl=fyb_news', '3582660', 202, '', '针对网传“提取年轻人血液、换血治疗”等谣言，海尔金控发布声明称，涉事“虞美人”集团及其董事长于文红与海尔无任何关联，海尔从未开展或参与相关业务，已固定证据并将追究法律责任。此前，虞美人集团创始人曾因无证行医被曝光，旗下公司曾因偷税被罚超8800万元。​​​​', '2026-03-31T02:04:09.664Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6708, 'toutiao-hot', '小伙在结婚前立遗嘱将房产留给父母', 'https://www.toutiao.com/trending/7622966537016049691/?category_name=topic_innerflow&event_type=hot_board&log_pb=%7B%22category_name%22%3A%22topic_innerflow%22%2C%22cluster_type%22%3A%220%22%2C%22enter_from%22%3A%22click_category%22%2C%22entrance_hotspot%22%3A%22outside%22%2C%22event_type%22%3A%22hot_board%22%2C%22hot_board_cluster_id%22%3A%227622966537016049691%22%2C%22hot_board_impr_id%22%3A%2220260401120345D04BEB98FA174FC68D50%22%2C%22jump_page%22%3A%22hot_board_page%22%2C%22location%22%3A%22news_hot_card%22%2C%22page_location%22%3A%22hot_board_page%22%2C%22source%22%3A%22trending_tab%22%2C%22style_id%22%3A%2240132%22%2C%22title%22%3A%22%E5%B0%8F%E4%BC%99%E5%9C%A8%E7%BB%93%E5%A9%9A%E5%89%8D%E7%AB%8B%E9%81%97%E5%98%B1%E5%B0%86%E6%88%BF%E4%BA%A7%E7%95%99%E7%BB%99%E7%88%B6%E6%AF%8D%22%7D&rank=&style_id=40132&topic_id=7622966537016049691', '0', 371, 'https://p3-sign.toutiaoimg.com/tos-cn-i-qvj2lq49k0/6d2f724e69e54c85872bf7924621b1dc~tplv-tt-shrink:960:540.jpeg?_iz=30575&from=sign_default&lk3s=8d617dac&x-expires=1777593600&x-signature=unakRGBd5akS5wRa0TyiLyePyQo%3D', '新事件上榜', '2026-03-31T23:24:30.744Z');
