INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5216, 'tencent-hot', '重庆地铁吐血女孩胡心瑶正在上海治疗，称其银行账户因频繁收到转账，遭人举报被暂时封了，靠跟朋友借钱医治，“将前往南京咨询换肾问题”', 'https://view.inews.qq.com/a/20260330A07U4I00', '0', 65, '', '记者获悉，因“地铁吐血后用外套擦干”得到大量关注和爱心捐赠的重庆女孩胡心瑶，目前正在上海求诊。记者联系上对方时，她正在上海仁济医院输液。她告诉记者，自己的银行账户因频繁收到转账遭人举报被暂时封了，只能等回到老家后才能处理。“目前手机微信还有一点点钱，主要是跟朋友借钱医治，等后面账户解封后再把钱取出来...', '2026-03-31T00:24:02.625Z');
