INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5194, 'tencent-hot', '郑丽文4月率团访问大陆，张荣恭、萧旭岑、连胜武等人将随行', 'https://view.inews.qq.com/a/20260331A020VD00', '0', 81, '', '中国国民党主席郑丽文30日上午召开记者会表示，将于4月7日至12日率团前往大陆访问。她强调，此次访问大陆将继续在国民党既定政策坚持“九二共识”、反对“台独”的基础上，“一分不多，一分不少”，向台湾人....', '2026-03-31T04:03:45.870Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6398, 'tencent-hot', '特朗普：美国将在两到三周内结束对伊朗战争', 'https://view.inews.qq.com/a/20260401A01GF400', '0', 157, '', '当地时间3月31日，美国总统特朗普表示，美国将在两到三周内结束对伊朗的战争，并称此举将有助于降低当前高企的能源价格。特朗普称，美方当前目标是“彻底摧毁伊朗剩余军事能力”，包括导弹设施及相关基础设施，并表示美国可能在“两周到三周内离开伊朗”，但也不排除在此之前通过谈判达成协议的可能。在霍尔木兹海峡问题上...', '2026-03-31T19:03:54.610Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5201, 'tencent-hot', '女子为出入地库伪造号牌，忘记摘除驶上高速被当场查获', 'https://view.inews.qq.com/a/20260331A04JPG00', '0', 120, '', '一女子因两辆车仅有一个小区地库车位，“灵机一动”伪造机动车号牌以便车辆进出，驶出地库后忘记摘除假牌便驾车上高速，在高速出口被收费员拦下。新黄河记者了解到，山东高速交警到场核查确认其伪造号牌违法行为，....', '2026-03-31T15:03:48.515Z');
