INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6737, 'tencent-hot', '联合国发布报告：中东冲突升级可能引发严重经济后果', 'https://view.inews.qq.com/a/20260401A025HE00', '0', 172, '', '△迪雅里克（资料图）3月31日，联合国秘书长发言人迪雅里克援引联合国开发计划署的最新报告，就中东地区军事冲突升级可能带来的严重经济后果发出强烈警告。迪雅里克表示，根据联合国开发计划署的报告分析，如果当前中东地区的军事冲突升级，很可能会给该地区带来1200亿美元至1940亿美元的经济损失，占该地区总体国内生产总...', '2026-03-31T22:03:48.212Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6907, 'tencent-hot', '视频丨陈志犯罪集团核心骨干成员李雄被从柬埔寨押解回国', 'https://view.inews.qq.com/a/20260401A03FLA00', '1632193', 31, '', '4月1日，在柬埔寨有关部门大力支持下，公安部派出工作组，成功将陈志犯罪集团核心骨干成员李雄从柬埔寨金边押解回国。这是中柬执法合作取得的又一重大战果。经查，李雄曾任太子集团旗下汇旺集团董事长，涉嫌开设赌场、诈骗、非法经营、掩饰隐瞒犯罪所得等多项犯罪。目前，李雄已被依法采取强制措施，相关案件正在进一步侦办中。公安部有关负责人表示，陈志犯罪集团已有多名骨干成员陆续到案，公安机关将继续加大工作力度，坚决将在逃人员缉捕归案。同时再次正告犯罪分子，认清形势、悬崖勒马，尽早投案自首，争取宽大处理。（总台央视记者 朱云） 新闻链接视频丨公安部：重大跨境赌诈犯罪集团头目陈志被从柬埔寨押解回国公安部敦促陈志犯罪集...', '2026-04-01T01:45:29.761Z');
