INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5214, 'tencent-hot', '水产专家建议这6种鱼少吃，重金属含量可能超标', 'https://view.inews.qq.com/a/20260331A00VIE00', '0', 90, '', '从营养角度来说，大多数鱼都富含优质蛋白质和多不饱和脂肪酸，但若论食用安全性和口感，不同鱼之间是有一定差距的。 水产专家很少吃6种鱼上海海洋大学食品学院教授陈舜胜建议，以下几种鱼最好少吃。■ 大型肉食性鱼类，可能富集重金属美国食品和药品管理局根据汞等重金属污染情况，将鱼分为三大类，陈舜胜根据我国实际情况进行了细分：不推荐食用：大西洋马鲛鱼、大目金枪鱼等大型肉食性鱼类。大型肉食性鱼类，可能富集重金属。随着食物链的传送，水体中的浮游生物、小型草食性鱼类、大型肉食性鱼类所含的重金属等污染物浓度逐级增高，呈现出明显的生物放大效应。普通推荐：石斑鱼、银鳕鱼、黄花鱼、大比目鱼、鲷鱼等海鱼，青鱼、鲢鱼、鳙鱼、...', '2026-03-31T06:03:50.562Z');
