INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5427, 'baidu-hot', '美国女子戴手铐从车窗逃脱警察未察觉', 'https://www.baidu.com/s?wd=%E7%BE%8E%E5%9B%BD%E5%A5%B3%E5%AD%90%E6%88%B4%E6%89%8B%E9%93%90%E4%BB%8E%E8%BD%A6%E7%AA%97%E9%80%83%E8%84%B1%E8%AD%A6%E5%AF%9F%E6%9C%AA%E5%AF%9F%E8%A7%89&sa=fyb_news&rsv_dl=fyb_news', '3213829', 250, '', '当地时间3月28日，社交平台上流传一段视频，记录了在密歇根州，一名女嫌疑人从警车逃脱的瞬间。画面显示，她戴着手铐从一辆警车敞开的车窗钻了出去，随即拔腿逃跑。这一切警方都没有发现。目前密歇根州警方尚未对此事件发表评论。', '2026-03-31T00:24:20.878Z');
