INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7366, 'tencent-hot', '充电桩涨价潮来袭？有人一次多花30元，但并非“全面普涨”，行业竞争有望告别“低价内卷”', 'https://view.inews.qq.com/a/20260401A06OCY00', '1220751', 51, '', '每经记者：孙桐桐 每经编辑：余婷婷“以前充一次电差不多50元，前几天居然花了80多元！”3月以来，全国多地公共充电桩价格悄然波动，核心商圈、高速服务区等热门点位的高峰时段电价涨幅尤为突出，不少新能源车主直呼“电车的成本优势要没了”，这一现象迅速引发热议，成为新能源车主圈的核心话题。《每日经济新闻》记者近日...', '2026-04-01T18:00:08.146Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7369, 'tencent-hot', '云南省委书记王宁，看望张桂梅老师', 'https://view.inews.qq.com/a/20260401A06EE400', '1198104', 53, '', '据《云南日报》消息，3月30日至4月1日，在习近平总书记考察云南时深入丽江调研一周年之际，省委书记王宁率队来到丽江市，与基层干部群众共同学习重温、深化落实习近平总书记考察云南重要讲话精神。     ....', '2026-04-01T18:00:08.146Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7370, 'tencent-hot', '“老头乐”开进地铁车厢？青岛地铁客服：正核查是否属残疾人代步工具', 'https://view.inews.qq.com/a/20260401V055IM00', '1184611', 54, '', '3月31日，青岛网民发布视频称有俗称“老头乐”的老年电动代步车开进了青岛地铁车厢，质疑此行为可能会有安全隐患。青岛地铁工作人员表示车厢允许残疾人助力车及电动轮椅等进入，不允许普通老年代步车进入，青岛地铁已接到相关情况反馈，并在对该“老头乐”是否属于残疾人代步工具进行核查。', '2026-04-01T18:00:08.146Z');
