INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7367, 'tencent-hot', '养女被养父母告上法庭索要此前赠与的购房购车款400余万元 一审法院驳回', 'https://view.inews.qq.com/a/20260401A06A6S00', '1231947', 50, '', '老两口李某和宁某此前是油田退休职工，曾收养一名养女直到养女大学毕业后才告知其身世。出于好奇，养女曾发帖寻找亲生父母，养父母阻挠，且因养女劝养父母谨慎理财，双方产生矛盾。后李某宁某夫妇以养女很少探望、未尽赡养义务为由告上法庭，索要此前转给养女的购房款、购车款等400余万元。红星新闻记者近日从裁判文书网了...', '2026-04-01T18:00:08.146Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7588, 'tencent-hot', '太原“暴走团”凌晨四点播放音乐扰民？当地通报', 'https://view.inews.qq.com/a/20260401A04NSC00', '1166150', 56, '', '太原市杏花岭区巨轮街道4月1日发布情况通报：近日，有市民反映辖区“暴走团”凌晨四点播放音乐扰民。我们高度重视，会同坝陵桥街道、辖区派出所迅速核实处置。经现场核实：该队伍现有成员百余人，日常参与健步走活动约二十人，固定活动时间为早上5：45至6：30，并使用音响外放设备，产生的噪音确实对周边居民正常休息造成影...', '2026-04-01T18:00:08.146Z');
