INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5197, 'tencent-hot', '外交部：近日中方有三艘船舶过航霍尔木兹海峡', 'https://view.inews.qq.com/a/20260331A052FG00', '0', 126, '', '新华社北京3月31日电（记者冯歆然、温馨）外交部发言人毛宁31日在例行记者会上答问时说，经同有关方面协调，近日中方有三艘船舶过航霍尔木兹海峡，我们对有关方面提供的协助表示感谢。霍尔木兹海峡及其附近水域是重要的国际货物和能源贸易通道，中方呼吁尽快停火止战，恢复海湾地区和平稳定。（完）来源：新华社...', '2026-03-31T15:03:48.515Z');
