INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6389, '36kr-hot', '机构、个人投资者“不约而同”，股票型基金获显著增持', '<![CDATA[https://36kr.com/newsflashes/3747497191686919?f=rss]]>', '0', 71, '', '公募基金2025年年报披露完毕，公募基金持有人全貌也随之展现。天相投顾数据显示：2025年下半年，机构投资者显著增持了股票型基金和混合型基金；个人投资者增持了股票型基金，但减持了混合型基金。从公募基金', '2026-03-31T16:04:02.470Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6658, 'baidu-hot', '给儿子找的甜美儿媳竟是41岁大汉', 'https://www.baidu.com/s?wd=%E7%BB%99%E5%84%BF%E5%AD%90%E6%89%BE%E7%9A%84%E7%94%9C%E7%BE%8E%E5%84%BF%E5%AA%B3%E7%AB%9F%E6%98%AF41%E5%B2%81%E5%A4%A7%E6%B1%89&sa=fyb_news&rsv_dl=fyb_news', '4368883', 135, '', '据悉，王大伯在某社交APP结识自称“芳芳”的“女性”。“芳芳”以儿媳自称获取王大伯信任后，虚构父亲心脏病等理由骗取其18万元。经警方查实，“芳芳”实为41岁男子沙某。目前，沙某因涉嫌诈骗罪已被依法采取刑事强制措施。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6643, '36kr-hot', '厦金“小三通”航线出入境旅客量突破2400万人次', '<![CDATA[https://36kr.com/newsflashes/3747650842362372?f=rss]]>', '0', 102, '', '截至今日10时，自2001年1月2日开通以来的厦金“小三通”航线，历经25年发展，累计出入境旅客量突破2400万人次大关。其中仅用半年时间即实现2300万至2400万的百万量级增长，刷新历史最快速度。', '2026-03-31T19:03:53.548Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5609, '36kr-hot', '上期所优化期权最后交易日未平仓单行权锁仓业务', '<![CDATA[https://36kr.com/newsflashes/3746624792298245?f=rss]]>', '0', 17, '', '36氪获悉，上期所发布通知，为提升操作便利性，上海国际能源交易中心对期权最后交易日未平仓单行权锁仓业务进行了优化，并定于2026年4月10日正式上线实施。 本次优化后，在期权最后交易日15:00至15', '2026-03-31T01:25:08.406Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6419, 'baidu-hot', '贾浅浅论文被指涉嫌抄袭其父贾平凹', 'https://www.baidu.com/s?wd=%E8%B4%BE%E6%B5%85%E6%B5%85%E8%AE%BA%E6%96%87%E8%A2%AB%E6%8C%87%E6%B6%89%E5%AB%8C%E6%8A%84%E8%A2%AD%E5%85%B6%E7%88%B6%E8%B4%BE%E5%B9%B3%E5%87%B9&sa=fyb_news&rsv_dl=fyb_news', '4267288', 141, '', '3月30日，有博主发帖称，贾浅浅于2014年6月发表的论文《生命的言说与意义一试论贾平凹的书法创作》中部分内容，与其父贾平凹1994年发表的《马治权的书法作品》一文高度相似，相同的语句跨越20年，被用于评述两位书法作者的风格。', '2026-03-31T23:05:26.297Z');
