INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6909, 'tencent-hot', '太原“暴走团”凌晨噪音扰民 警方称市民可电话报警 派出所：已约谈负责人', 'https://view.inews.qq.com/a/20260401A03DOX00', '0', 179, '', '近日，山西太原市杏花岭区一支“暴走团”引发网友广泛关注。有网友发布视频称，该团队每日凌晨四点在城区街道列队健走，同时使用音响外放音乐，严重干扰周边居民正常休息。 ▲网友拍摄的暴走团画面网友拍摄的视频显示，天色未亮、路灯照明下，20余名身穿橙红色统一服装的人员在太原市杏花岭区五一路与北中环街交叉口南侧的...', '2026-03-31T23:24:36.401Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5770, 'baidu-hot', '王楚钦正反手夯爆了', 'https://www.baidu.com/s?wd=%E7%8E%8B%E6%A5%9A%E9%92%A6%E6%AD%A3%E5%8F%8D%E6%89%8B%E5%A4%AF%E7%88%86%E4%BA%86&sa=fyb_news&rsv_dl=fyb_news', '3315247', 231, '', '3月31日，2026年国际乒联单打世界杯小组赛继续进行。王楚钦3-0横扫罗马尼亚选手约内斯库，取得了本届世界杯开门红。‌‌比赛中王楚钦正反手夯爆了！全是一击制胜，对手顶不住，王皓骄傲鼓掌。', '2026-03-31T15:04:07.795Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6664, 'baidu-hot', '全网寻找的“甘蔗哥”康复出摊了', 'https://www.baidu.com/s?wd=%E5%85%A8%E7%BD%91%E5%AF%BB%E6%89%BE%E7%9A%84%E2%80%9C%E7%94%98%E8%94%97%E5%93%A5%E2%80%9D%E5%BA%B7%E5%A4%8D%E5%87%BA%E6%91%8A%E4%BA%86&sa=fyb_news&rsv_dl=fyb_news', '3104602', 267, '', '此前，四川成都一段“男子全网寻找楼下卖甘蔗大哥”的视频，牵动了众多网友的心，后面得知大哥生病了，所以没出摊。近日，甘蔗大哥已病愈出摊，据悉，其出摊位置没发生变化，还有不少市民特意赶来支持。', '2026-03-31T19:04:12.827Z');
