INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5610, '36kr-hot', 'Nebius斥资100亿美元在芬兰建设AI数据中心，进一步拓展欧洲市场', '<![CDATA[https://36kr.com/newsflashes/3746621848912390?f=rss]]>', '0', 16, '', '人工智能基础设施企业Nebius集团周二宣布，将在芬兰新建一座310兆瓦的数据中心，持续推进其在欧洲的快速扩张。随着人工智能算力需求不断增长，该数据中心估值超100亿美元，将成为欧洲规模最大的数据中心', '2026-03-31T01:25:08.406Z');
