INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5844, '36kr-hot', 'IPO中止，蓝箭航天回应：因申报材料中财务资料已过有效期', '<![CDATA[https://36kr.com/newsflashes/3746760139506435?f=rss]]>', '0', 45, '', '3月31日，上交所官网显示，蓝箭航天科创板IPO中止。对此，蓝箭航天回应称，上交所网站显示的“中止”，系因公司申报材料中引用的财务资料已过有效期，需要补充提交更新后的相关财务资料及申报文件，属于程序性', '2026-03-31T04:03:44.785Z');
