INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5757, '36kr-hot', '央行：2月同业拆借日均成交4293.2亿元，同比增加87.1%', '<![CDATA[https://36kr.com/newsflashes/3746712279286532?f=rss]]>', '0', 37, '', '36氪获悉，央行数据显示，2026年2月，同业拆借日均成交4293.2亿元，同比增加87.1%；银行间市场债券回购日均成交7.4万亿元，同比增加52.9%。2026年2月末，同业拆借未到期余额1.0万', '2026-03-31T03:03:53.791Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7350, 'tencent-hot', '看见2030“十五五”新图景丨脑机接口加速落地 拓展多元应用新场景', 'https://view.inews.qq.com/a/20260401A04Z1B00', '2359462', 6, '', '脑机接口，是“十五五”期间我国要着重发力的未来产业之一。在上海，已经集聚近60家脑机接口企业，搭建起从核心器件研发、技术攻关、临床转化验证到商业化落地的全链条产业生态。那么目前脑机接口能实现哪些功能、具体在做什么方向的攻关。 小鼠实验 见证“纳米森林”唤醒视觉总台记者 陈阳：我现在在复旦大学脑科学研究院...', '2026-04-01T18:00:08.146Z');
