INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7352, 'tencent-hot', '成交量狂飙翻倍！北上广深二手房集体井喷，喜提“小阳春”', 'https://view.inews.qq.com/a/20260401A0797G00', '2270341', 8, '', '深入调整多年的一线城市房地产市场，在刚过去的3月份喜提楼市“小阳春”。广州二手住宅网签套数破万套，环比大增141.38%；深圳一二手商品房合计成交11851套，环比上升117.1%；北京二手住宅3月共19886套，环比上升144.63%，创近15个月来最高峰值；上海二手房累计网签量达3.13万套，创2021年3月以来近五年的最高纪录，市场热...', '2026-04-01T18:00:08.146Z');
