INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5761, 'tencent-hot', '新兴市场资产或迎2020年来最差月度，有机构开始抄底', 'https://view.inews.qq.com/a/20260331A04TKD00', '0', 77, '', '受中东冲突持续的影响，今年稍早最热门交易之一的新兴市场资产可能即将录得2020年以来最差月度走势。不过，在部分机构已开始抄底之际，也有不少市场人士认为，新兴市场资产仍具有投资吸引力。 走势背后的逻辑 2月28日爆发的中东冲突终结了此前新兴市场股市和本币债券的强劲上涨势头。今年前两个月，新兴市场股市和本币债券...', '2026-03-31T03:03:54.911Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5852, 'tencent-hot', '受贿数额特别巨大 中国证监会原副主席王建军被提起公诉', 'https://view.inews.qq.com/a/20260331A02H9F00', '0', 119, '', '记者今天（31日）从最高人民检察院获悉，中国证券监督管理委员会原党委委员、副主席王建军涉嫌受贿一案，由国家监察委员会调查终结，移送检察机关审查起诉。最高人民检察院依法以涉嫌受贿罪对王建军作出逮捕决定，并指定由山东省潍坊市人民检察院审查起诉。近日，潍坊市人民检察院已向潍坊市中级人民法院提起公诉。检察机关...', '2026-03-31T14:03:43.875Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6027, 'tencent-hot', '湖北籍红军烈士牺牲93年，亲属千里接其“回家”：终于完成家人遗愿', 'https://view.inews.qq.com/a/20260331A07R3H00', '0', 109, '', '“二伯，爸爸去世的时候托付我一定要找到你，现在我来接你回家了。”3月31日，湖北红安籍红军烈士张泽艳的亲属第一次赴四川巴中认亲、祭祀。张泽艳侄儿张克争来到墓前祭拜。图/九派新闻 杨冰钰张泽艳烈士生于1912年，1931年3月加入中国工农红军，曾任红四军三十团政委，1933年9月在四川巴州(中)作战中英勇牺牲，年仅21岁，安葬于川陕革命根据地红军烈士陵园（原名王坪红军烈士墓，始建于1934年）。因战争年代条件限制、信息匮乏，家属多年未能寻得亲人安葬之处。2018年，川陕革命根据地红军烈士陵园发布了寻亲信息。2023年底，亲属在红安军烈情志愿服务队志愿者的帮助下发现线索，经过走访排查，2024年春...', '2026-03-31T14:03:43.875Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6093, 'tencent-hot', '白金汉宫宣布：英国国王查尔斯三世将对美国进行国事访问', 'https://view.inews.qq.com/a/20260331A07SNS00', '0', 128, '', '【环球网报道 记者 张江平】综合美联社等媒体报道，白金汉宫3月31日宣布，英国国王查尔斯三世将对美国进行国事访问。查尔斯三世 资料图 图源：外媒白金汉宫当天在一份声明中称，根据英国政府建议，同时应美国总统邀请，英国国王查尔斯三世与王后卡米拉将对美国进行国事访问。美联社称，这将是查尔斯三世首次对美国进行国事...', '2026-03-31T15:03:48.515Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6732, 'tencent-hot', '亚洲股市全线大涨！美伊齐释和平意愿 全球开启“反弹模式”', 'https://view.inews.qq.com/a/20260401A02M5900', '0', 164, '', '财联社4月1日讯（编辑 潇湘）随着美国和伊朗均释放出有意结束中东冲突的信号，周三(4月1日)全球市场风险偏好情绪进一步回暖，亚太股市纷纷追随隔夜美股大涨。行情数据显示，日经225指数在今日开盘后不久涨幅就扩大至约4%。韩国市场的表现则要更为惊人——开盘后不久KOSPI 200期货涨幅就超过5%，促使韩国交易所启动KOSPI指数...', '2026-03-31T21:03:49.987Z');
