INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6731, 'tencent-hot', '联大高票通过，中国投下赞成票', 'https://view.inews.qq.com/a/20260401A01IXC00', '1577486', 36, '', '联大通过改进联合国授权任务相关决议，古特雷斯称有历史意义当地时间3月31日，联合国大会高票通过题为《为建设高效且有效的联合国而进行的授权任务制定、执行与审查》的决议。表决结果为168票赞成、4票反对、0票弃权。中国投下赞成票，俄罗斯、白俄罗斯、朝鲜和尼加拉瓜投了反对票。联合国秘书长古特雷斯对该决议的通过表示...', '2026-04-01T01:45:29.761Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6404, 'tencent-hot', '29岁女孩“解冻”，蔡磊期待的“破冰”转折点来临？', 'https://view.inews.qq.com/a/20260331A084Z900', '1523146', 38, '', '2026年1月30日，蔡磊（图：南方人物周刊记者 梁辰）2026年1月1日，蔡磊在自己创建的渐冻症患者组织平台“渐愈互助之家”（以下简称“渐愈”）公众号上发布公开信，宣称“团队数年来与中国科学家合作推进的SOD1等基因类型渐冻症的治疗药物，实现了领先世界的临床前和临床疗效，对SOD1患者来说，渐冻症这个200年的恶魔已被‘...', '2026-04-01T01:45:29.761Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6275, 'tencent-hot', '就诊购药记录被大数据筛查，“买过助眠药”的网友称收到注销驾照短信', 'https://view.inews.qq.com/a/20260330A08KK500', '0', 106, '', '极目新闻记者 杜光然近日，一条通知注销驾驶证的短信备受关注，短信写道：（湖里交警大队）因大数据比对分析显示，您可能存在器质性心脏病、癫痫病、美尼尔氏症、眩晕症、癔病、震颤麻痹、精神病、痴呆以及影响肢体活动的神经系统疾病等相关的就诊或购药记录。根据《道路交通安全法》及《机动车驾驶证申领和使用规定》，上...', '2026-03-31T13:03:44.620Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5204, 'tencent-hot', '视频丨规范殡葬领域明码标价、防范“天价”收费 这一规定5月31日起试行', 'https://view.inews.qq.com/a/20260331A03MW100', '0', 68, '', '记者今天（31日）了解到，市场监管总局会同民政部印发《殡葬领域明码标价规定（试行）》，为各类经营者明码标价提供分类指引。《规定》将殡仪馆、公墓、骨灰堂等殡葬服务机构，销售殡葬用品的经营主体以及其他从事殡葬相关服务活动的组织和个人全部纳入殡葬领域经营者范围，覆盖“逝、殡、葬、祭”各环节，不留监管盲区。《规定》立足监管执法实践，进一步细化明码标价要求。既有一般性规定，也有特别规定，有针对性地破除丧属和经营者之间信息差。其中，一般性规定是全部殡葬领域经营者需要共同遵守的，特别规定是对殡仪馆、公墓、骨灰堂、殡葬中介等不同类型经营者和骨灰盒、寿衣、墓位（格位）安葬、祭奠场地租赁等特定商品和服务分别适用的...', '2026-03-31T01:25:09.529Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5760, 'tencent-hot', '误以为是网红餐厅，俩外国小伙闯入百岁老人喜丧现场“蹭饭”', 'https://view.inews.qq.com/a/20260330A072HG00', '0', 100, '', '近日，美国网红Ludwig（路德维希）和同伴麦克的一段中国摩旅视频，在外网掀起了一阵讨论热潮，播放量突破百万。视频里，两个金发碧眼的外国人误将湖南农村的喜丧酒席认作网红餐厅，用蹩脚中文问出“可以吃吗”，一位大哥用英文夹中文的方式和他们全程交流，让无数网友忍俊不禁；而后续这位大哥的暖心相助，又让不少人感动得...', '2026-03-31T09:03:47.146Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6403, 'tencent-hot', '地铁吐血女孩胡心瑶银行账户已解封，正前往南京咨询换肾问题', 'https://view.inews.qq.com/a/20260331A07DNS00', '0', 141, '', '3月31日，现代快报记者获悉，因“地铁吐血后用外套擦干”得到大量关注和爱心捐赠的女孩胡心瑶，此前其银行账户因频繁收到转账遭人举报被封。截至31日下午4点多，其账户在大家的帮助下已经解封。“很多人都很关心我，下午我收到银行的工作人员来电，告诉我账户已经解封，我们重庆当地的政府部门也跟我联系了，了解情况后协助...', '2026-03-31T16:04:03.544Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5190, 'tencent-hot', '时政现场说丨厚植生态底色 共绘锦绣中国', 'https://view.inews.qq.com/a/20260331A027G500', '0', 79, '', '3月30日，习近平等党和国家领导人来到北京市昌平区百善镇，同干部群众一起参加义务植树。 挥锹铲土、培土围堰、提水浇灌……习近平接连种下油松、北京牡丹、榆叶梅、杜仲、元宝枫等多棵树苗。 植树期间，习近平询问孩子们的学习生活、劳动锻炼和参加植树情况，并同在场的干部群众亲切交谈。 植树造林是美丽中国建设的一项重...', '2026-03-31T04:03:45.870Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6019, 'tencent-hot', '苏和任内蒙古自治区副主席，么永波辞去副主席职务', 'https://view.inews.qq.com/a/20260331A07GF400', '0', 97, '', '3月31日，内蒙古自治区第十四届人民代表大会常务委员会第二十七次会议决定任命：苏和为自治区人民政府副主席。      苏和，男，蒙古族，1970年1月出生，大学，农业推广硕士，中共党员，现任内蒙古自....', '2026-03-31T07:04:07.259Z');
