INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5845, 'tencent-hot', '清明节假期7座以下（含7座）小客车高速免收通行费', 'https://view.inews.qq.com/a/20260331A06CEK00', '0', 94, '', '据交通运输部消息，2026年清明节假期，7座以下（含7座）小型客车上高速公路继续免收通行费，免费通行时间为4月4日0时至4月6日24时，共计3天。 免费时间怎么算？高速公路以车辆驶离收费站收费车道的时间为准。走人工通道上高速，不建议在ETC车道下高速。建议各位车主尽量选择同一类型车道（即在哪个通道上的就在哪个通道下），以免造成不必要的麻烦，尤其是ETC车辆。特别是在人工通道上的高速，下高速时不要选择ETC通道，否则将无法正常通行，因没有入口信息，出口栏杆机不会抬杆，只能折返至人工车道驶出。2026中央广播电视总台版权所有。未经许可，请勿转载使用。', '2026-03-31T07:04:07.259Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6319, 'tencent-hot', '伊朗：结束战争的决定，取决于伊朗', 'https://view.inews.qq.com/a/20260331A01H1H00', '0', 123, '', '图为3月30日的伊朗首都德黑兰城市面貌。图片由在伊中国公民提供据伊朗迈赫尔通讯社报道，伊朗总统佩泽希齐扬30日表示，任何关于结束战争的决定，都将在充分考虑“所有提出的条件”之后，并在维护伊朗民族尊严、国家安全和人民利益的基础上作出。同一天，伊朗军方也表示，伊朗将决定战争的结束。图为3月30日的伊朗首都德黑兰...', '2026-03-31T15:03:48.515Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5683, 'tencent-hot', '港媒：韩国芯片巨头加大对华投资', 'https://view.inews.qq.com/a/20260331A05FQL00', '0', 93, '', '参考消息网3月31日报道 据香港《南华早报》网站3月29日报道，面对人工智能（AI）算力需求造成的存储芯片市场供应趋紧，三星电子公司与SK海力士公司正加大对华投资以扩大供应。这表明，即便在美国限制之下，中国仍是半导体生产中的关键一环。报道称，根据3月10日提交给韩国金融监督院的年度报告，三星电子2025年对其西安芯片...', '2026-03-31T06:03:50.562Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6570, 'tencent-hot', '游客同里古镇景区拍照遭商家驱赶抢夺手机，官方：涉事商户停业整改', 'https://view.inews.qq.com/a/20260401A01JIT00', '0', 154, '', '同里旅游官微消息，同里镇政府4月1日通报，近日，网传“游客同里古镇景区拍照遭商家驱赶”，引发关注。经核查，3月29日下午，一名游客因拍照遭商家驱赶抢夺手机引发肢体冲突，报案后，属地派出所及时依法处置，商户向游客进行了赔偿。针对涉事商户，已责成其停业整改。对于此次事件给游客带来的不良体验，我们深表歉意。...', '2026-03-31T19:03:54.610Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5851, 'tencent-hot', '张雪机车夺冠，浙江国资赢麻了', 'https://view.inews.qq.com/a/20260331A035T700', '0', 95, '', '葡萄牙波尔蒂芒赛道，中国摩托车品牌见证历史时刻——来自重庆的张雪机车（ZXMOTO）厂队车手瓦伦丁·德比斯，驾驶820RR-RS赛车，接连斩获世界超级摩托车锦标赛（WSBK）SSP中量级组别两回合冠军。比赛中，瓦伦丁驾驶的张雪机车以超3.6秒的优势，力压杜卡迪、雅马哈、川崎等国际老牌强队，成为中国摩托制造商在WSBK这一顶级赛...', '2026-03-31T07:04:07.259Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7347, 'tencent-hot', '人民之心｜起决定性作用的是党性', 'https://view.inews.qq.com/a/20260401A05NY400', '531263', 63, '', '编者按：政绩观，是世界观、人生观、价值观在为政实践中的集中体现。在全党开展树立和践行正确政绩观学习教育之际，央视网《习语品读》特别推出系列报道，围绕习近平总书记关于树立和践行正确政绩观的重要论述，与您一起学习正确政绩观的丰富内涵与实践要求。 4月1日，《求是》杂志发表习近平总书记的重要文章《树立和践行...', '2026-04-01T18:00:08.146Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5937, 'tencent-hot', '权威数读丨3月份， PMI三大指数均重返扩张区间', 'https://view.inews.qq.com/a/20260331A0556O00', '0', 152, '', '国家统计局服务业调查中心、中国物流与采购联合会31日发布3月份PMI指数。数据显示，3月份，随着春节后复工复产加快，产需两端同步扩张，制造业采购经理指数、非制造业商务活动指数和综合PMI产出指数均重返扩张区间，分别为50.4%、50.1%和50.5%，比上月上升1.4个、0.6个和1.0个百分点，我国经济景气水平回升。统筹：曹建礼制...', '2026-03-31T18:04:05.601Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7371, 'tencent-hot', '茅台缺席春糖酒店展，酒企都在焦虑一个事：为何年轻人不爱喝酒了', 'https://view.inews.qq.com/a/20260401A04WYD00', '997963', 62, '', '图源：视觉中国      文 ｜ 吴遮      编辑 ｜ 孙春芳      出品 ｜ 棱镜·腾讯小满工作室      3月26日，成都的气温明显回升，久违的阳光也回来了。      这一天，第11....', '2026-04-01T17:41:31.532Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7382, 'baidu-hot', '河北查处31名高收入人员', 'https://www.baidu.com/s?wd=%E6%B2%B3%E5%8C%97%E6%9F%A5%E5%A4%8431%E5%90%8D%E9%AB%98%E6%94%B6%E5%85%A5%E4%BA%BA%E5%91%98&sa=fyb_news&rsv_dl=fyb_news', '6473903', 51, '', '2025年，国家税务总局河北省税务局依法查处31名高收入、高净值人员（含网络主播）偷逃税案件，查补税款8859万元，同期还查处高风险加油站158户、涉嫌虚开骗税企业3400余户。', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7380, 'baidu-hot', '伊朗：新最高领袖因战争推迟公开露面', 'https://www.baidu.com/s?wd=%E4%BC%8A%E6%9C%97%EF%BC%9A%E6%96%B0%E6%9C%80%E9%AB%98%E9%A2%86%E8%A2%96%E5%9B%A0%E6%88%98%E4%BA%89%E6%8E%A8%E8%BF%9F%E5%85%AC%E5%BC%80%E9%9C%B2%E9%9D%A2&sa=fyb_news&rsv_dl=fyb_news', '6757536', 42, '', '据伊朗方面4月1日消息，伊朗外交部发言人巴加埃在接受媒体采访时说，伊朗最高领袖穆杰塔巴·哈梅内伊身体健康，但因战争推迟公开露面。', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7381, 'baidu-hot', '幼儿园小朋友裹被子开溜被老师抓包', 'https://www.baidu.com/s?wd=%E5%B9%BC%E5%84%BF%E5%9B%AD%E5%B0%8F%E6%9C%8B%E5%8F%8B%E8%A3%B9%E8%A2%AB%E5%AD%90%E5%BC%80%E6%BA%9C%E8%A2%AB%E8%80%81%E5%B8%88%E6%8A%93%E5%8C%85&sa=fyb_news&rsv_dl=fyb_news', '6560773', 49, '', '4月1日，一名幼儿园小朋友在午休时间裹着被子试图离开，被老师当场发现。据家长描述，孩子性格活泼，事后因担心批评而否认行为。', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7400, 'baidu-hot', '伊朗首都德黑兰发生爆炸', 'https://www.baidu.com/s?wd=%E4%BC%8A%E6%9C%97%E9%A6%96%E9%83%BD%E5%BE%B7%E9%BB%91%E5%85%B0%E5%8F%91%E7%94%9F%E7%88%86%E7%82%B8&sa=fyb_news&rsv_dl=fyb_news', '4831273', 113, '', '当地时间4月1日17时03分，伊朗首都德黑兰发生爆炸。爆炸分别发生在德黑兰东部地区和西部地区，有当地居民反馈，爆炸造成部分区域停电。', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7393, 'baidu-hot', '山西一煤业公司发生冒顶事故4人遇难', 'https://www.baidu.com/s?wd=%E5%B1%B1%E8%A5%BF%E4%B8%80%E7%85%A4%E4%B8%9A%E5%85%AC%E5%8F%B8%E5%8F%91%E7%94%9F%E5%86%92%E9%A1%B6%E4%BA%8B%E6%95%854%E4%BA%BA%E9%81%87%E9%9A%BE&sa=fyb_news&rsv_dl=fyb_news', '4741811', 118, '', '记者从山西省吕梁市兴县有关部门获悉，4月1日21时15分，中煤关家崖煤业有限公司发生一起冒顶事故，有4人被困。2日2时46分，被困4人被救援升井，已无生命体征。', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7591, 'baidu-hot', '11岁女孩被取出4.5公斤巨型恶性肿瘤', 'https://www.baidu.com/s?wd=11%E5%B2%81%E5%A5%B3%E5%AD%A9%E8%A2%AB%E5%8F%96%E5%87%BA4.5%E5%85%AC%E6%96%A4%E5%B7%A8%E5%9E%8B%E6%81%B6%E6%80%A7%E8%82%BF%E7%98%A4&sa=fyb_news&rsv_dl=fyb_news', '4650171', 122, '', '', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7403, 'baidu-hot', '12岁哥哥教科书式报警找回走失弟弟', 'https://www.baidu.com/s?wd=12%E5%B2%81%E5%93%A5%E5%93%A5%E6%95%99%E7%A7%91%E4%B9%A6%E5%BC%8F%E6%8A%A5%E8%AD%A6%E6%89%BE%E5%9B%9E%E8%B5%B0%E5%A4%B1%E5%BC%9F%E5%BC%9F&sa=fyb_news&rsv_dl=fyb_news', '4545009', 127, '', '日前，苏州太仓一名12岁男孩在父母外出时独自照看7岁弟弟，发现弟弟走失后，用家中旧手机冷静拨打110，清晰描述弟弟衣着特征并提供照片。民警迅速出警，成功找回走失儿童。', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7406, 'baidu-hot', '工地巨型钻头从天而降 行人险被砸中', 'https://www.baidu.com/s?wd=%E5%B7%A5%E5%9C%B0%E5%B7%A8%E5%9E%8B%E9%92%BB%E5%A4%B4%E4%BB%8E%E5%A4%A9%E8%80%8C%E9%99%8D+%E8%A1%8C%E4%BA%BA%E9%99%A9%E8%A2%AB%E7%A0%B8%E4%B8%AD&sa=fyb_news&rsv_dl=fyb_news', '4473614', 129, '', '4月1日，广西百色市田阳区住房和城乡建设局发布情况通报称，2026年3月31日，该区红棉路荣鑫苑片区排水防涝项目施工现场，发生施工钻头倾倒事件，无人员伤亡。相关视频引发网友关注。', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7408, 'baidu-hot', '黄金年内回撤达26%', 'https://www.baidu.com/s?wd=%E9%BB%84%E9%87%91%E5%B9%B4%E5%86%85%E5%9B%9E%E6%92%A4%E8%BE%BE26%25&sa=fyb_news&rsv_dl=fyb_news', '4352512', 137, '', '2026年3月，伦敦黄金现货价格从5598美元/盎司的历史高位暴跌至4099美元，年内回撤达26%，单日最大跌幅超8%。随后快速反弹至4500美元以上。此次波动由美联储鹰派政策、霍尔木兹海峡运输受阻推高油价，以及获利盘集中了结等多重因素导致。', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7412, 'baidu-hot', '今麦郎董事长回应“手打”是商标', 'https://www.baidu.com/s?wd=%E4%BB%8A%E9%BA%A6%E9%83%8E%E8%91%A3%E4%BA%8B%E9%95%BF%E5%9B%9E%E5%BA%94%E2%80%9C%E6%89%8B%E6%89%93%E2%80%9D%E6%98%AF%E5%95%86%E6%A0%87&sa=fyb_news&rsv_dl=fyb_news', '4259958', 145, '', '', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7407, 'baidu-hot', '美军向中东增派18架A-10攻击机', 'https://www.baidu.com/s?wd=%E7%BE%8E%E5%86%9B%E5%90%91%E4%B8%AD%E4%B8%9C%E5%A2%9E%E6%B4%BE18%E6%9E%B6A-10%E6%94%BB%E5%87%BB%E6%9C%BA&sa=fyb_news&rsv_dl=fyb_news', '4178386', 147, '', '当地时间4月1日，记者获悉，美国国防部正将其在中东部署的空军A-10攻击机机队规模扩大一倍。两名五角大楼官员当日透露，美国空军正派遣18架A-10攻击机前往中东，加入该地区已有的十几架同型机行列。', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7411, 'baidu-hot', '郑丽文再次表态反“台独”', 'https://www.baidu.com/s?wd=%E9%83%91%E4%B8%BD%E6%96%87%E5%86%8D%E6%AC%A1%E8%A1%A8%E6%80%81%E5%8F%8D%E2%80%9C%E5%8F%B0%E7%8B%AC%E2%80%9D&sa=fyb_news&rsv_dl=fyb_news', '4082227', 155, '', '中国国民党主席郑丽文将于4月7日率团访问大陆，行前再次明确表态反对“台独”，强调坚持“九二共识”是两岸和平交流的政治基础，称此行意义重大、挑战非凡，希望能带来两岸的春天！', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7409, 'baidu-hot', '开春炸江！黑龙江数十米冰雾腾空而起', 'https://www.baidu.com/s?wd=%E5%BC%80%E6%98%A5%E7%82%B8%E6%B1%9F%EF%BC%81%E9%BB%91%E9%BE%99%E6%B1%9F%E6%95%B0%E5%8D%81%E7%B1%B3%E5%86%B0%E9%9B%BE%E8%85%BE%E7%A9%BA%E8%80%8C%E8%B5%B7&sa=fyb_news&rsv_dl=fyb_news', '3989411', 161, '', '随着春季日渐升温，冰封一冬的黑龙江即将迎来开江时刻。为防止开江期发生冰凌卡塞、冰坝堆积等情况引发凌汛灾害，4月1日，大兴安岭呼玛县、塔河县对境内黑龙江重点江段开展人工防凌汛爆破作业，保障沿江人民群众生命财产安全。', '2026-04-01T17:41:34.155Z');
