INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5219, 'tencent-hot', '10后小孩哥把妈妈“骂”他的话写成歌，网友听懵：笑着笑着就哭了', 'https://view.inews.qq.com/a/20260330A06JMN00', '0', 98, '', '近日，一位10后小男孩创作的一首歌曲在网上走红。据了解，该歌的歌词全部来自妈妈平时“骂”他的话。网友纷纷调侃：“这是《听妈‘骂’的话》。”视频显示，男孩说道：“这是一首用我妈骂我的话写下的歌。”紧接着，一连串熟悉的“家长语录”扑面而来：“快快，为什么总是等到来不及才快？”“你看你做什么都慢总手忙脚乱。...', '2026-03-31T08:03:44.922Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7108, 'sspai-hot', 'Agent 的家：如何在 AI 时代搭建硬件基座', 'https://sspai.com/post/108064', '0', 9, '', 'Matrix首页推荐Matrix是少数派的写作社区，我们主张分享真实的产品体验，有实用价值的经验与思考。我们会不定期挑选Matrix最优质的文章，展示来自用户的最真实的体验和观点。文章代表作者个人观点', '2026-04-01T18:00:06.583Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7384, 'baidu-hot', '义务教育摇号“可以操作”系谣言', 'https://www.baidu.com/s?wd=%E4%B9%89%E5%8A%A1%E6%95%99%E8%82%B2%E6%91%87%E5%8F%B7%E2%80%9C%E5%8F%AF%E4%BB%A5%E6%93%8D%E4%BD%9C%E2%80%9D%E7%B3%BB%E8%B0%A3%E8%A8%80&sa=fyb_news&rsv_dl=fyb_news', '6848385', 40, '', '近日，成都有家长接到电话称义务教育摇号“可以操作”，交钱即可选择学校。当地教育部门回应，这属于典型诈骗手段，利用家长焦虑心理牟利，摇号录取全过程随机且无法人为干预。相关部门提醒家长提高警惕，遇到类似情况及时举报。', '2026-04-01T17:41:34.155Z');
