INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6908, 'tencent-hot', '视频丨国台办：和平统一后 台湾同胞再也无需为各种能源物资短缺而焦虑', 'https://view.inews.qq.com/a/20260401A02J9Y00', '0', 171, '', '4月1日，国台办举行例行新闻发布会。有记者问：台媒报道，受中东战事影响，台湾石油供应紧张，连带冲击塑料原料市场，因而近期岛内掀起一股“抢塑潮”，未来可能还有“缺药潮”。岛内舆论指出，面对这些困境，民进党当局只会说“油气供应无虞”，而应对危机永远慢半拍。对此有何评论？发言人张晗表示，民进党当局所谓的“油气供应无虞”不过是对“油气供应无力”的自我安慰，更是对大众的愚弄欺骗。民进党当局应对岛内民生危机无心无力，只会一味逃避，台湾社会各界早已对此强烈不满。和平统一后，两岸实现互联互通、应通尽通，大陆完整的产业体系和稳定的市场供应能力将成为台湾同胞最坚实的依靠，完全可以弥补台湾在原油、天然气、工业原料等...', '2026-03-31T22:03:48.212Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6318, 'tencent-hot', '纯牛奶倒出疑似透明苦水？官方通报：同批次产品召回封存，将全面排查', 'https://view.inews.qq.com/a/20260331A07P3Y00', '0', 121, '', '“共和融媒”消息，3月31日，青海省共和县市场监督管理局发布情况通报：3月30日，针对媒体反映“青海雪峰牦牛乳业有限责任公司生产的高原纯牛奶产品包装内出现透明液体”的问题，共和县市场监督管理局高度重视，第一时间成立调查组，进驻生产企业开展全面调查，同步启动同批次产品召回封存工作，对企业纯牛奶系列备样产品抽...', '2026-03-31T15:03:48.515Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6492, 'tencent-hot', '外卖油麦菜里现30多只虫子？店方称已保留当天油麦菜，市监局介入', 'https://view.inews.qq.com/a/20260331V0806E00', '0', 151, '', '3月30日，山西临汾陈先生称点的外卖中发现油麦菜里有32只虫子。31日，陈先生说当时吃了约三分之一才发现有虫子，最后从菜叶里挑出三十几只。涉事外卖店人员称，店方会摘菜、洗菜、炒菜，多个工作人员经手查看，“不可能有那么多虫子”，当时其他两单点油麦菜的顾客未反映有虫子。该人员称，他们保留了一份当天的油麦菜，并主动联系12315平台。当地市监局已介入。', '2026-03-31T18:04:05.601Z');
