INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7356, 'tencent-hot', '百年建筑“吴佩孚公馆”转卖背后：隐秘交易与被私吞的千万巨款', 'https://view.inews.qq.com/a/20260402A01GEL00', '1426165', 43, '', '新京报记者 韩福涛 编辑 胡杰 校对 刘军武汉市江岸区南京路124号，是一栋被武汉市政府列为一级保护的优秀历史建筑，据说民国军阀吴佩孚曾在此居住，因而有“吴佩孚公馆”之名，另一个官方称谓为吴家花园。百年来，这栋建筑历经多次转手，如今成了网红民宿。十年前，围绕这栋建筑曾有过一桩隐秘交易。2016年，这栋建筑当时的...', '2026-04-01T18:00:08.146Z');
