INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7360, 'tencent-hot', '河南俩老人存银行10万元，取钱只有7万元？中信银行回应', 'https://view.inews.qq.com/a/20260401A063OQ00', '1681942', 26, '', '“本是去存钱，结果却变成了保险。”近日，市民郭女士反映，其父母此前在中信银行焦作分行办理“养老储蓄”业务，每月存入500元，累计投入近10万元，事后才发现并非存款，而是保险产品，一旦退保将损失3万余元。郭女士认为，父母是在工作人员误导、隐瞒风险的情况下非自愿购买，涉事方涉嫌违规销售。反映：存款变保险，10万元如果取出将损失3万多据郭女士介绍，其父母分别于2017年7月、2018年2月开始，每月在焦作中信银行存入500元。当时银行工作人员介绍，该行有一款强制储蓄、养老补充产品，每月存500元，连续存10年，到期利率高于同期银行存款，其间还附送保险。2025年10月，她陪同母亲到中信银行办理业务时...', '2026-04-01T18:00:08.146Z');
