INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7163, 'tencent-hot', '应急管理部中国消防救援学院、北方航空护林总站等划入国家消防救援局', 'https://view.inews.qq.com/a/20260401A04P7Z00', '1466292', 41, '', '近日，应急管理部官网公布了《应急管理部2026年度部门预算》。其中，“灾害防治及应急管理支出（类）应急管理事务（款）应急管理（项）”披露，2026年预算数为71291.63万元，比2025年执行数减少9916.59万元，下降12.21%，主要是北方航空护林总站、南方航空护林总站、中国消防救援学院划入国家消防救援局，2026年预算相应减...', '2026-04-01T01:45:29.761Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6735, 'tencent-hot', '西湖景区游客和保安互吐口水；管理处：游客发小广告制止不住发生争吵，已对保安进行了教育', 'https://view.inews.qq.com/a/20260401A02MNM00', '0', 178, '', '3月31日，网友发布视频称，在浙江杭州西湖风景名胜区，看到有游客和景区保安发生争吵，随后，两人还互相喷起口水。      视频里，游客穿浅色衣服，戴红色帽子，保安身穿制服。两人挨得很近，能看见互吐口....', '2026-03-31T23:24:36.401Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6392, 'tencent-hot', '视频丨电池有了专属“身份证”！全国动力电池溯源平台今日上线', 'https://view.inews.qq.com/a/20260401A01G5M00', '0', 156, '', '今天（1日），全国新能源汽车动力电池溯源信息平台正式上线，将为我国新能源汽车产业绿色循环发展提供国家级信息平台支撑。记者看到，这一平台以动力电池的数字身份信息为核心载体，通过对每一块动力电池进行编码，上线产业链上下游的数据信息，实现了对动力电池流向的链式追溯。专家表示，这一信息平台涵盖四大核心功能，...', '2026-03-31T19:03:54.610Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6397, 'tencent-hot', '俄罗斯一架运输机坠毁 29人遇难', 'https://view.inews.qq.com/a/20260401A01EMS00', '0', 175, '', '新华社符拉迪沃斯托克4月1日电（记者孙萍）据俄新社4月1日援引俄国防部消息报道，俄罗斯一架安-26型运输机在克里米亚地区因技术故障坠毁，6名机组人员和23名乘客全部遇难。（完）...', '2026-03-31T23:05:09.778Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5210, 'tencent-hot', '男子买手打挂面没吃出手打面感觉，今麦郎：手打挂面“手打”只是商标', 'https://view.inews.qq.com/a/20260330A08QQN00', '0', 113, '', '近日，南京的陈先生在超市购买一款手打挂面，回家后没吃出手打面的感觉，查看外包装后才发现，所谓“手打”挂面只是商家玩的文字游戏。对此，今麦郎食品公司工作人员回应称，挂面是生产车间制作，“手打”只是取的名而已。记者调查发现，类似的“心机商标”还真不少：树上采的椰子水中“树上采的”实际上是待审商标； 配料...', '2026-03-31T14:03:43.875Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6026, 'tencent-hot', '“中国以外很难”，一句话让美国政府砸掉16亿美元', 'https://view.inews.qq.com/a/20260331A05VIE00', '0', 138, '', '【文/观察者网 阮佳琪】在对稀土资源高度依赖的焦虑下，特朗普政府不惜采取高风险、高争议的激进投资手段，试图打破中国在稀缺战略金属领域的主导地位，以构建本土关键矿产供应链。然而，英国媒体最近发现，这些获得政府资助的企业，在技术成熟度、财务健康状况与政治透明度三方面都面临着严峻考验。据《金融时报》30日报道...', '2026-03-31T16:04:03.544Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6408, 'tencent-hot', '视频丨印尼16岁以下人群“社媒禁令”生效', 'https://view.inews.qq.com/a/20260401A01E9S00', '0', 139, '', '印度尼西亚政府日前宣布，从3月28日起正式实施针对16岁以下人群的社交媒体禁令，以防范青少年陷入网络色情、网络欺凌、网络诈骗和网络成瘾等问题。印尼政府要求所有在该国运营的社交媒体平台作出调整，遵守新规。印尼通信和数字事务部长 默蒂娅·哈菲兹：政府已指示在印尼运营的所有数字平台立即调整其产品、功能和服务，以...', '2026-03-31T16:04:03.544Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5202, 'tencent-hot', '钱七虎院士再认捐100万', 'https://view.inews.qq.com/a/20260331A046Q900', '0', 130, '', '据苏州日报消息，3月30日下午，89岁的中国工程院院士、“八一勋章”获得者钱七虎再次向“瑾晖”慈善基金认捐100万元。截至目前，钱七虎个人累计捐赠已突破2500万元。“瑾晖”慈善基金是以钱七虎院士的母亲和妻子名字命名。如今，这个名字已成为跨越山河的爱心纽带。自2013年基金设立以来，钱院士已将国家最高科学技术奖800...', '2026-03-31T15:03:48.515Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5208, 'tencent-hot', '伊朗议会批准对霍尔木兹海峡征收通行费的法案', 'https://view.inews.qq.com/a/20260331A00W1F00', '0', 111, '', '总台记者获悉，当地时间3月30日，伊朗议会国家安全委员会通过了拟对霍尔木兹海峡通行船只收费的法案。计划内容包括将以伊朗里亚尔形式实施财务安排和收费系统；将禁止美国和以色列的船只通过霍尔木兹海峡；将维护伊朗及其武装部队的主导地位；将禁止对伊朗进行单边制裁的国家的船只通行；伊朗将与阿曼合作制定相关法律框架。（总台记者 李健南 赵远方）2026中央广播电视总台版权所有。未经许可，请勿转载使用。', '2026-03-31T14:03:43.875Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6274, 'tencent-hot', '“大力士”力箭二号运载火箭首飞告捷 将满足低轨通信卫星星座组网', 'https://view.inews.qq.com/a/20260331A01HH600', '0', 131, '', '3月30日19时00分，力箭二号遥一运载火箭在东风商业航天创新试验区发射升空。2026年3月30日19时00分，酒泉卫星发射中心，东风商业航天创新试验区，中科宇航力箭二号遥一运载火箭成功首飞。南都记者了解到，力箭二号是我国首款“通用助推器核心”(Common Booster Core， CBC)构型的运载火箭，由总部来自广州的商业航天企业中...', '2026-03-31T15:03:48.515Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5203, 'tencent-hot', '视频丨禁烧区焚烧依旧 秸秆治理如何破局', 'https://view.inews.qq.com/a/20260329A05UEL00', '0', 118, '', '就在不久前，刚刚审议通过的《生态环境法典》对秸秆、落叶等焚烧管理作出进一步规定，引发社会关注，法典提出地方各级人民政府应当科学精准加强秸秆、落叶等焚烧的组织、指导和管理。同时，禁止在人口集中地区、机场周围、交通干线附近露天焚烧此类产生烟尘污染的物质。这一规定与2025年中央一号文件提出的“支持秸秆综合利用，精准划定禁烧范围，依法依规落实禁烧管控要求”相呼应，标志着我国从早期的“全面禁烧”向精细化的管理转变。然而记者经过近5个月实地调查，发现黑龙江、吉林等多地，诸如机场、高速路周围等禁烧区域出现了“不让烧”却又“无人管”，焚烧秸秆依旧的现象，给生态环境治理、人民生命财产安全埋下了隐患。秸秆禁烧区...', '2026-03-31T14:03:43.875Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5205, 'tencent-hot', '中国科协发布《告示》', 'https://view.inews.qq.com/a/20260331A042O200', '0', 70, '', '学者参加2026年人工智能领域国际学术会议NeurIPS，不纳入中国科协资助范围；对2026年该会议收录论文，不直接作为成果采信……3月31日，中国科学技术协会发布《告示》重申，就上述会议发表的声明，没有发生变化。中国科学技术协会近日，NeurIPS（神经信息处理系统大会）在其2026年会议征稿指南中，公然依据美国单边制裁名单...', '2026-03-31T02:03:51.981Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5686, 'tencent-hot', '学生疑因携带泡面入校被拦？广西都安通报', 'https://view.inews.qq.com/a/20260330A08PGK00', '0', 86, '', '都安瑶族自治县教育局3月30日通报，近日，网传视频称“广西河池一学校保安被曝用测试仪检查学生随身携带物品，一女生因一包泡面被拦下”，教育局高度重视，立即组织人员开展核查。现将有关情况通报如下：2026年3月25日下午6时，都安瑶族自治县实验中学保安在执行日常入校安全检查时，发现一名外宿学生欲带方便面入校。根据...', '2026-03-31T05:03:51.879Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7005, 'tencent-hot', '原特斯拉中国区高管孔艳双入职小米，汽车零售将迎来体系化整合', 'https://view.inews.qq.com/a/20260401A03GWH00', '2258361', 9, '', '界面新闻记者 | 李家琦界面新闻编辑 | 文姝琪 4月1日，界面新闻独家获悉，原特斯拉中国区总经理孔艳双已入职小米，将接替原小米汽车总监李晓锐负责汽车销售方面工作。孔艳双于3月初入职，处于工作交接期，目前小米内部并未正式发文通告其正式职位。界面新闻就以上消息向小米求证，截至发稿，小米暂无回应。公开资料显示，孔...', '2026-04-01T01:45:29.761Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7127, 'tencent-hot', '总台报道有反馈丨广东市场监管、海关、公安三部门对“优思益”展开调查', 'https://view.inews.qq.com/a/20260401A04EE100', '2045452', 14, '', '今天（1日），总台报道“进口”保健品乱象，“澳洲优思益”号称进口，实为国内生产。节目播出后，广东市场监管、海关、公安三部门联合行动，对“优思益”等所谓“进口”保健品所属的广州雅拉源健康产业有限公司展开调查。今天上午九点，当记者来到广州雅拉源健康产业有限公司，当地市场监管部门已经到达现场，对这家公司进行取证和固证等相关工作，随后将对有关产品进行执法抽检。海关和公安部门执法人员同步展开调查。浙江市场监管部门对杭州索象营销策划有限公司展开调查今天上午9时许，浙江杭州滨江区市场监管部门对杭州索象营销策划有限公司开展了现场调查。当地市场监管部门对杭州索象与广州雅拉源之间业务关系等资料进行调查取证。（总台...', '2026-04-01T01:45:29.761Z');
