INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5193, 'tencent-hot', '【“十五五”新图景】增绿降碳 加减之间再造万亿级新机遇', 'https://view.inews.qq.com/a/20260331A02NY700', '0', 82, '', '“十五五”规划纲要中提出，加快经济社会发展全面绿色转型。当前，一场增绿降碳的变革正在重塑我们的生产生活方式，持续激发绿色发展动能。粤西海域，离岸70公里外，水深超50米，一场绿色能源的“接力”正在加紧进行。规范有序推进深远海风电开发，首次被写入“十五五”规划纲要。新一个五年里，我国海上风电累计并网装机规...', '2026-03-31T04:03:45.870Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5935, 'tencent-hot', '习近平：树立和践行正确政绩观', 'https://view.inews.qq.com/a/20260331A050BI00', '0', 150, '', '树立和践行正确政绩观※习近平一我们讲宗旨，讲了很多话，但说到底还是为人民服务这句话。我们党就是为人民服务的。中央的考虑，是要为人民做事。各级干部也不能眼睛总是向上。任何事情都要向上看看，向下看看。要经常问问自己，我们是不是在忙着与党的根本宗旨毫不相关的事情？有没有一心一意在为老百姓做事情？是不是在围绕党和国家中心任务而工作？古时候讲，食君之禄，忠君之事。现在就是要服务人民。（2012年12月29日、30日在河北省阜平县考察扶贫开发工作时的讲话）二概括起来说，好干部要做到信念坚定、为民服务、勤政务实、敢于担当、清正廉洁。信念坚定，党的干部必须坚定共产主义远大理想，真诚信仰马克思主义，矢志不渝为中...', '2026-03-31T18:04:05.601Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6491, 'tencent-hot', '军事机密泄露，竟是因为它？', 'https://view.inews.qq.com/a/20260401A01E7400', '0', 174, '', '据微信公众号“国家安全部”4月1日消息，近日，某国发生一起因智能穿戴设备导致的军事机密泄露事件，引发全球关注。当时该国某重要军事装备正在执行任务，一名军官跑步时佩戴的智能运动手表持续记录并公开了高精度GPS数据，致使该军事装备实时位置等重要敏感信息泄露，给该国国防安全造成难以弥补的重大损失，也让智能穿戴...', '2026-03-31T23:05:09.778Z');
