INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6646, 'tencent-hot', '新华视点｜春耕一线见闻：科技春耕 智绘沃野', 'https://view.inews.qq.com/a/20260331A0557L00', '0', 181, '', '■春涌天山 智耕沃野 新疆春耕春播全面展开 眼下，天山南北田间地头一派繁忙景象，新疆各地抢抓农时、有序推进春播生产。智能农机驰骋田野，良种良法配套落地，新技术、新装备、新模式广泛应用，让新疆现代农业发展底色愈发鲜明。 在巴音郭楞蒙古自治州轮台县的高标准棉田里，北斗导航无人驾驶播种机来回穿梭，覆膜、播种、...', '2026-03-31T23:24:36.401Z');
