INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5847, 'tencent-hot', '贺青，升任上海市副市长', 'https://view.inews.qq.com/a/20260331A06ZQV00', '0', 134, '', '据“上海人大”微信公众号消息，上海市十六届人大常委会第二十九次会议今天（3月31日）通过有关人事任免事项，决定任命贺青为上海市副市长。贺青此前担任上海市国资委党委书记、主任。贺青 资料图公开资料显示，贺青出生于1972年2月，籍贯湖南湘潭，他长期在金融领域工作，曾任上海银行副行长、党委委员，中国太平洋保险（...', '2026-03-31T15:03:48.515Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6394, 'tencent-hot', '中国拉了一个叫“WDO”的群', 'https://view.inews.qq.com/a/20260331A06S6F00', '0', 169, '', '一个新的国际组织，落户北京。3月30日，世界数据组织（World Data Organization）正式成立，英文简称“WDO”。图片来源：央视新闻。很多人第一眼看到WDO，会联想到WTO，虽有一字之差，但来头可不小，它是全球首个旨在推动数据发展与治理实践的专业性国际组织。人们关心，这个组织到底是干什么的？WDO的宗旨是“弥合数据鸿沟...', '2026-03-31T22:03:48.212Z');
