INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6094, 'tencent-hot', '中国驻米兰总领馆通报关于留学生黄某失联案的最新情况', 'https://view.inews.qq.com/a/20260331A07VID00', '0', 116, '', '关于留学生黄某失联案的最新情况通报3月30日，我馆接意大利宪兵通报称，意北部多洛米蒂山区富内斯山谷雪地中发现一具遗体，其衣物装备与此前失联的中国留学生黄某基本一致，身上发现黄某护照。目前，意方需进一步确认身份。我馆已第一时间向当事人家属通报上述情况。失联案发生以来，我馆一直与意方保持密切沟通，督促其全力开展搜寻工作。下步，我馆将继续密切关注案情进展，并向家属提供必要协助。', '2026-03-31T14:03:43.875Z');
