INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6739, 'tencent-hot', '4月1日起一批国家标准正式实施', 'https://view.inews.qq.com/a/20260401A02CIL00', '0', 183, '', '记者今天从国家标准委了解到，4月1日起，一批国家标准开始实施，将为引领和规范新兴产业及未来产业的发展、推动传统产业升级、提升交通运输和游览服务质量、保护消费者权益等提供标准支撑。《光伏发电站继电保护技术要求》规定了光伏发电站继电保护的总体要求、配置要求、整定要求及整定管理要求。《分布式光伏发电系统远程监控技术规范》规定了分布式光伏发电系统远程监控系统的正常工作条件、系统架构、技术要求、检测试验方法，以及标志、包装、运输和贮存等内容。《光伏发电站安全规程》规定了光伏发电站设备设施、运行、检修维护的安全要求。三项标准的实施，有利于进一步规范并网光伏电站的继电保护、远程监控和运行维护工作，支撑新型电...', '2026-03-31T23:24:36.401Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6740, 'tencent-hot', '多家机票代理收到通知：国内航线燃油附加费4月5日起涨5倍', 'https://view.inews.qq.com/a/20260401A02TDZ00', '0', 184, '', '【多家机票代理收到通知：国内航线燃油附加费4月5日起涨5倍 800公里以上调百元】财联社4月1日电，记者获悉，多家机票代理已收到厦门航空，中联航通知，国内航线燃油附加费拟自4月5日上调，其中800公里(含)以下航段收取60元，800公里以上航段120元。目前800公里(含)以下航段收取燃油费10元，800公里以上航段20元，意味着国内...', '2026-03-31T23:24:36.401Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7124, 'tencent-hot', '人民日报：张雪的逆袭是一部不折不扣的奋斗史', 'https://view.inews.qq.com/a/20260330A08UF600', '1883193', 19, '', '北京时间3月28日，世界超级摩托车锦标赛（WSBK）赛场上，中国摩托车品牌张雪机车以近4秒的绝对优势夺冠，一举打破了杜卡迪、雅马哈、川崎等国际豪强对该组别长达数十年的垄断。这一刻，远在重庆观看直播的创始人张雪热泪盈眶。次日（29日）进行的第二回合中，张雪机车再次拿下胜利，实现两连胜。这不仅是中国摩托车登上世界顶级赛事之巅的“高光时刻”，更是一段生动诠释“爬坡过坎”的飞驰人生。回望来路，张雪的逆袭是一部不折不扣的奋斗史。20年前，19岁的湖南农村穷小子张雪，为了心里的机车梦，冒雨骑行100多公里，“死缠烂打”地追逐电视台节目组，只为求一个被车队看见的机会。他做过修车铺里指甲缝嵌满黑机油的学徒，也...', '2026-04-01T01:45:29.761Z');
