INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6020, 'tencent-hot', '山西省委：坚决拥护党中央决定', 'https://view.inews.qq.com/a/20260331A07NMI00', '0', 186, '', '3月30日，中央纪委国家监委网站通报，山西省人大常委会原党组成员、副主任岳普煜涉嫌严重违纪违法，目前正接受中央纪委国家监委纪律审查和监察调查。（此前报道）据山西综合广播消息，3月31日，山西省委常委会召开扩大会议，通报岳普煜涉嫌严重违纪违法，目前正接受中央纪委国家监委纪律审查和监察调查。与会同志一致表示，...', '2026-03-31T23:24:36.401Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6567, 'tencent-hot', '销冠“澳洲优思益”实为纯国产，央视曝光：销量数百万瓶，记者赴澳发现地址竟是一家汽修站，幕后推手称“广州的包装成澳洲的”', 'https://view.inews.qq.com/a/20260401A01RLC00', '0', 187, '', '随着公众对健康的重视，保健品经常出现在大家的购物车中，特别是一些进口保健品，从保税仓直接发货、有明星代言和各种国际奖项，备受消费者青睐。其中，叶黄素进口保健品在网购平台卖得很火，抖音、天猫销量第一的叶黄素知名品牌“澳洲优思益”原产地标称为澳大利亚，此前有消费者对其产地提出质疑。带着消费者的疑问，总台...', '2026-03-31T23:24:36.401Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6406, 'tencent-hot', '视频丨从“九天”到“长鹰” 盘点我国无人空天硬核力量', 'https://view.inews.qq.com/a/20260401A01D6Q00', '0', 149, '', '3月31日长鹰-8大型运输无人机成功完成首飞成为全球迄今首飞的最大货运无人机从可指挥无人机蜂群的“九天苍穹”到载重3.5吨的“长鹰-8”我国无人空天硬核实力不断增强一起来了解四位“空中大力士” “空中母舰”九天苍穹2025年12月11日，“九天苍穹”无人航空通用平台在陕西成功首飞。作为我国自主创新、性能位居世界前列的大型通用无人机平台，它不仅体形庞大，更可以作为“空中母舰”指挥无人机蜂群，也能挂载重磅武器进行精确打击，真正具备了“从天而降”的威慑力。“九天苍穹”无人航空通用平台是围绕“九天”灵活配置重型无人机构建的无人航空通用平台。以其6吨的载重能力和90千瓦的能源供给，可搭载各类大型专业设备...', '2026-03-31T17:04:08.064Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5218, 'tencent-hot', '残缺污损人民币兑换办法今起正式施行', 'https://view.inews.qq.com/a/20260331A028CL00', '0', 67, '', '中国人民银行发布的《中国人民银行残缺污损人民币兑换办法》自今日起正式施行。 该办法首次系统明确了残缺、污损人民币的界定标准，清晰划分了可兑换与不可兑换的边界，将兑换情形更加细化。兑换业务由中国人民银行分支机构指定的金融机构无偿办理。 2026中央广播电视总台版权所有。未经许可，请勿转载使用。', '2026-03-31T00:24:02.625Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5762, 'tencent-hot', '教育部：高校要新设一批适应新技术、新产业、新业态的学科专业', 'https://view.inews.qq.com/a/20260331A05P4200', '0', 76, '', '教育部今天（31日）举行国家教育数字化战略行动2026年部署会。教育部部长怀进鹏指出，要持续开发丰富国家智慧教育平台资源，依托人工智能技术，建设更加智能化、个性化的资源和工具，赋能学生学习，助力个性化成长与学习。立足促进学生德智体美劳全面发展，建立全息、全域、全员、全时的沉浸式思政育人模式，探索人工智能赋...', '2026-03-31T03:03:54.911Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7421, 'baidu-hot', '被AI短剧盗脸成丑角 女模特发声', 'https://www.baidu.com/s?wd=%E8%A2%ABAI%E7%9F%AD%E5%89%A7%E7%9B%97%E8%84%B8%E6%88%90%E4%B8%91%E8%A7%92+%E5%A5%B3%E6%A8%A1%E7%89%B9%E5%8F%91%E5%A3%B0&sa=fyb_news&rsv_dl=fyb_news', '3294011', 240, '', '3月31日，博主“七海Christ”发文称，其照片被短剧《桃花簪》未经授权用于AI生成角色形象，并被设定为丑角反派，质疑侵犯肖像权和名誉权。4月1日，平台回应已介入核查处理，相关片段已被替换。该博主表示不会和解，要求片方及平台赔偿并公开道歉。', '2026-04-01T17:02:26.907Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7422, 'baidu-hot', '公司给面试者发66元红包：过不过都发', 'https://www.baidu.com/s?wd=%E5%85%AC%E5%8F%B8%E7%BB%99%E9%9D%A2%E8%AF%95%E8%80%85%E5%8F%9166%E5%85%83%E7%BA%A2%E5%8C%85%EF%BC%9A%E8%BF%87%E4%B8%8D%E8%BF%87%E9%83%BD%E5%8F%91&sa=fyb_news&rsv_dl=fyb_news', '3236823', 243, '', '苏州蓝豚互动自今年年后起，给各地分公司面试者发放66元面试红包，明确规定无论面试是否通过均会发放，寓意六六大顺，以此表达对求职者的尊重与心意，该举措引发网友热议，也展现了公司对人才的关怀。', '2026-04-01T17:02:26.907Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6503, 'baidu-hot', '89岁院士钱七虎累计捐赠超2500万元', 'https://www.baidu.com/s?wd=89%E5%B2%81%E9%99%A2%E5%A3%AB%E9%92%B1%E4%B8%83%E8%99%8E%E7%B4%AF%E8%AE%A1%E6%8D%90%E8%B5%A0%E8%B6%852500%E4%B8%87%E5%85%83&sa=fyb_news&rsv_dl=fyb_news', '4565274', 123, '', '3月30日，89岁的中国工程院院士、“八一勋章”获得者钱七虎再次向“瑾晖慈善基金”认捐100万元。截至目前，钱七虎个人累计捐赠已突破2500万元，惠及人数超2000人次。', '2026-03-31T17:04:28.395Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5858, 'baidu-hot', '伊朗高层向美国发出密集警告', 'https://www.baidu.com/s?wd=%E4%BC%8A%E6%9C%97%E9%AB%98%E5%B1%82%E5%90%91%E7%BE%8E%E5%9B%BD%E5%8F%91%E5%87%BA%E5%AF%86%E9%9B%86%E8%AD%A6%E5%91%8A&sa=fyb_news&rsv_dl=fyb_news', '3881550', 171, '', '近日，伊朗高官密集发声，就美军可能发动地面战发出严厉警告。伊朗最高领袖外事顾问韦拉亚提说，敌人对伊朗任何地区的地面入侵，都将遭遇“历史性”失败。伊朗第一副总统阿雷夫说，特朗普只能决定向哈尔克岛派兵，但这些人员能否返回，将不再由他说了算。', '2026-03-31T16:04:21.744Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6745, 'baidu-hot', '李荣浩回应抄袭风波', 'https://www.baidu.com/s?wd=%E6%9D%8E%E8%8D%A3%E6%B5%A9%E5%9B%9E%E5%BA%94%E6%8A%84%E8%A2%AD%E9%A3%8E%E6%B3%A2&sa=fyb_news&rsv_dl=fyb_news', '7041999', 32, '', '4月1日，李荣浩发文回应抄袭风波：首先我要说，我没有抄袭。在歌曲《小眼睛》的问题上，我认为已经超越抄袭。这就是那首歌原曲，换了位歌手唱了一遍。这件事一定会有结果，大家等我消息。', '2026-03-31T20:04:10.909Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5387, 'baidu-hot', '香港演员施明病逝 曾演紫衫龙王', 'https://www.baidu.com/s?wd=%E9%A6%99%E6%B8%AF%E6%BC%94%E5%91%98%E6%96%BD%E6%98%8E%E7%97%85%E9%80%9D+%E6%9B%BE%E6%BC%94%E7%B4%AB%E8%A1%AB%E9%BE%99%E7%8E%8B&sa=fyb_news&rsv_dl=fyb_news', '4164181', 150, '', '香港资深演员施明于3月21日清晨因病离世，享年74岁。其子李泳汉已向媒体证实死讯。曾在《倚天屠龙记》饰演紫衫龙王。', '2026-03-31T01:25:26.445Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6413, 'baidu-hot', '00后女孩留学回来当职业扫墓人', 'https://www.baidu.com/s?wd=00%E5%90%8E%E5%A5%B3%E5%AD%A9%E7%95%99%E5%AD%A6%E5%9B%9E%E6%9D%A5%E5%BD%93%E8%81%8C%E4%B8%9A%E6%89%AB%E5%A2%93%E4%BA%BA&sa=fyb_news&rsv_dl=fyb_news', '3993447', 160, '', '据悉，一洛阳00后女孩小白留学回国后当职业扫墓人。因为临近清明，小白平均每天要代祭10位逝者，鞠躬上百次。但每一次祭扫，她都不会有丝毫马虎。', '2026-03-31T20:04:10.909Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7417, 'baidu-hot', '储殷谈“文科无用论”', 'https://www.baidu.com/s?wd=%E5%82%A8%E6%AE%B7%E8%B0%88%E2%80%9C%E6%96%87%E7%A7%91%E6%97%A0%E7%94%A8%E8%AE%BA%E2%80%9D&sa=fyb_news&rsv_dl=fyb_news', '3390674', 227, '', '', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5381, 'baidu-hot', '春日经济供需两旺活力足', 'https://www.baidu.com/s?wd=%E6%98%A5%E6%97%A5%E7%BB%8F%E6%B5%8E%E4%BE%9B%E9%9C%80%E4%B8%A4%E6%97%BA%E6%B4%BB%E5%8A%9B%E8%B6%B3&sa=fyb_news&rsv_dl=fyb_news', '7618664', 6, '', '春风拂面，暖意融融，走出家门的人越来越多，和朋友们踏青出行共赴“花”海，尽享惬意时光。一幅欣欣向荣的春日消费图景正在铺展开来。从文旅体验到乡村休闲，从品质生活到绿色消费，多元业态蓬勃生长，烟火气与新鲜感交织，春日经济供需两旺、活力十足。', '2026-03-31T04:04:06.774Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5618, 'baidu-hot', '一户外品牌宣布收取“地球使用费”', 'https://www.baidu.com/s?wd=%E4%B8%80%E6%88%B7%E5%A4%96%E5%93%81%E7%89%8C%E5%AE%A3%E5%B8%83%E6%94%B6%E5%8F%96%E2%80%9C%E5%9C%B0%E7%90%83%E4%BD%BF%E7%94%A8%E8%B4%B9%E2%80%9D&sa=fyb_news&rsv_dl=fyb_news', '3988675', 162, '', '3月30日，Patagonia品牌开启“地球使用费”活动，要求消费者在购物时预付一笔物流包装费（首件15元，每加一件5元），收货后不退货可退还费用，若退货则扣除费用并捐赠给环保项目，引发热议。', '2026-03-31T07:04:28.019Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5421, 'baidu-hot', '晓华理发店流量退潮 留给怀化什么', 'https://www.baidu.com/s?wd=%E6%99%93%E5%8D%8E%E7%90%86%E5%8F%91%E5%BA%97%E6%B5%81%E9%87%8F%E9%80%80%E6%BD%AE+%E7%95%99%E7%BB%99%E6%80%80%E5%8C%96%E4%BB%80%E4%B9%88&sa=fyb_news&rsv_dl=fyb_news', '4099373', 152, '', '2024年，湖南理发师晓华因“听得懂话”爆红，也让怀化成为“最懂你的城市”。流量退去，周边商户们守着本心，也期盼着新的契机出现，让生意可以更好，让城市更受瞩目。', '2026-03-31T02:04:09.664Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5420, 'baidu-hot', '张雪回应禁止新手买820RR摩托车', 'https://www.baidu.com/s?wd=%E5%BC%A0%E9%9B%AA%E5%9B%9E%E5%BA%94%E7%A6%81%E6%AD%A2%E6%96%B0%E6%89%8B%E4%B9%B0820RR%E6%91%A9%E6%89%98%E8%BD%A6&sa=fyb_news&rsv_dl=fyb_news', '3506146', 208, '', '近日，张雪机车在世界超级摩托车锦标赛两天两冠后，吸引了市场和消费者的关注，张雪820RR也成为了明星车型。在接受采访时，张雪机车创始人张雪再回应“禁止新手购买820RR”一事，称自己希望少死几个人。', '2026-03-31T05:04:26.574Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5694, 'baidu-hot', '独身女子去世 600万遗产由民政局管理', 'https://www.baidu.com/s?wd=%E7%8B%AC%E8%BA%AB%E5%A5%B3%E5%AD%90%E5%8E%BB%E4%B8%96+600%E4%B8%87%E9%81%97%E4%BA%A7%E7%94%B1%E6%B0%91%E6%94%BF%E5%B1%80%E7%AE%A1%E7%90%86&sa=fyb_news&rsv_dl=fyb_news', '3495678', 213, '', '3月31日，上海市徐汇区人民法院当庭宣判，指定徐汇区民政局为独身去世的邓女士（53岁）的遗产管理人，负责处置其约600万元的遗产。', '2026-03-31T17:04:28.395Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5955, 'baidu-hot', '男子出国前3月突发脑梗退机票被拒', 'https://www.baidu.com/s?wd=%E7%94%B7%E5%AD%90%E5%87%BA%E5%9B%BD%E5%89%8D3%E6%9C%88%E7%AA%81%E5%8F%91%E8%84%91%E6%A2%97%E9%80%80%E6%9C%BA%E7%A5%A8%E8%A2%AB%E6%8B%92&sa=fyb_news&rsv_dl=fyb_news', '3785777', 181, '', '近日，江苏镇江的胡女士陷入难题。她花费2.4万余元在去哪儿网平台购买的6张上海往返马尔代夫的机票，因同行友人男子突发脑梗、医嘱明确“半年内不宜乘机”，申请退票时遭遇波折。航司认为“出发前有可能康复”，初审通过后拒退。', '2026-03-31T15:04:07.795Z');
