INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6751, 'baidu-hot', '国台办回应郑丽文即将访问大陆', 'https://www.baidu.com/s?wd=%E5%9B%BD%E5%8F%B0%E5%8A%9E%E5%9B%9E%E5%BA%94%E9%83%91%E4%B8%BD%E6%96%87%E5%8D%B3%E5%B0%86%E8%AE%BF%E9%97%AE%E5%A4%A7%E9%99%86&sa=fyb_news&rsv_dl=fyb_news', '3693545', 190, '', '4月1日，针对国民党主席郑丽文即将要访问大陆一事，国台办发言人张晗表示，中国国民党郑丽文主席就任以来，多次表达希望来大陆访问的意愿。我们将与国民党方面就郑丽文主席来访事宜进行沟通，作出妥善的安排。', '2026-03-31T22:40:49.014Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6747, 'baidu-hot', '连续10年 张雪公司团建是去骑摩托车', 'https://www.baidu.com/s?wd=%E8%BF%9E%E7%BB%AD10%E5%B9%B4+%E5%BC%A0%E9%9B%AA%E5%85%AC%E5%8F%B8%E5%9B%A2%E5%BB%BA%E6%98%AF%E5%8E%BB%E9%AA%91%E6%91%A9%E6%89%98%E8%BD%A6&sa=fyb_news&rsv_dl=fyb_news', '3589606', 199, '', '近日，随着张雪机车“一举夺魁”，其公司的相关新闻屡见不鲜。据悉，张雪公司春节放10天假，还连续10年放假团建去骑摩托车。张雪坦言：“中国春节放假是最长的，用来玩、用来打牌、用来吃太浪费了，用来骑摩托车多好。”', '2026-03-31T22:40:49.014Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5407, 'baidu-hot', '尹正回应“张雪要送其夺冠车型”', 'https://www.baidu.com/s?wd=%E5%B0%B9%E6%AD%A3%E5%9B%9E%E5%BA%94%E2%80%9C%E5%BC%A0%E9%9B%AA%E8%A6%81%E9%80%81%E5%85%B6%E5%A4%BA%E5%86%A0%E8%BD%A6%E5%9E%8B%E2%80%9D&sa=fyb_news&rsv_dl=fyb_news', '4263732', 143, '', '近日，演员尹正发文恭喜张雪机车夺冠，并表示自己要用行动支持！随后，张雪称要赠送夺冠车型给尹正。对此，尹正回应道：“我自己买，不能‘连吃带拿’。”', '2026-03-31T02:04:09.664Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5402, 'baidu-hot', '月嫂“带菌”上户 宝妈婴儿均被感染', 'https://www.baidu.com/s?wd=%E6%9C%88%E5%AB%82%E2%80%9C%E5%B8%A6%E8%8F%8C%E2%80%9D%E4%B8%8A%E6%88%B7+%E5%AE%9D%E5%A6%88%E5%A9%B4%E5%84%BF%E5%9D%87%E8%A2%AB%E6%84%9F%E6%9F%93&sa=fyb_news&rsv_dl=fyb_news', '4928904', 108, '', '花16800元请月嫂，本想为体质较弱的宝宝添一份专业照护，南昌市民肖女士却陷入维权困局。据悉，上户月嫂体检显示幽门螺旋杆菌阳性，平台不仅未充分告知，还在用药后未过复查期便出具“阴性”结果让月嫂上岗。随后，肖女士及孩子也被确诊阳性。', '2026-03-31T02:04:09.664Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5396, 'baidu-hot', '国足0-2喀麦隆 开场9分钟连丢2球', 'https://www.baidu.com/s?wd=%E5%9B%BD%E8%B6%B30-2%E5%96%80%E9%BA%A6%E9%9A%86+%E5%BC%80%E5%9C%BA9%E5%88%86%E9%92%9F%E8%BF%9E%E4%B8%A22%E7%90%83&sa=fyb_news&rsv_dl=fyb_news', '3211480', 252, '', '3月31日，中国男足在墨尔本举行的国际足联系列赛中以‌0-2‌负于喀麦隆队，开场‌3分钟‌被艾永低射破门，‌9分钟‌时阿里乌姆利用角球再进一球，五后卫阵型暴露防守漏洞。‌‌', '2026-03-31T10:04:11.431Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5621, 'baidu-hot', '人民日报评张雪：奋斗是逆天改命密码', 'https://www.baidu.com/s?wd=%E4%BA%BA%E6%B0%91%E6%97%A5%E6%8A%A5%E8%AF%84%E5%BC%A0%E9%9B%AA%EF%BC%9A%E5%A5%8B%E6%96%97%E6%98%AF%E9%80%86%E5%A4%A9%E6%94%B9%E5%91%BD%E5%AF%86%E7%A0%81&sa=fyb_news&rsv_dl=fyb_news', '3314738', 233, '', '北京时间3月28日，世界超级摩托车锦标赛（WSBK）赛场上，中国摩托车品牌张雪机车以近4秒的绝对优势夺冠。回望来路，张雪的逆袭是一部不折不扣的奋斗史。张雪用实力证明：做难而正确的事，哪怕荆棘满途，也能在赛道上堂堂正正地赢。', '2026-03-31T07:04:28.019Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6866, 'baidu-hot', '20块的老古董有线耳机火了', 'https://www.baidu.com/s?wd=20%E5%9D%97%E7%9A%84%E8%80%81%E5%8F%A4%E8%91%A3%E6%9C%89%E7%BA%BF%E8%80%B3%E6%9C%BA%E7%81%AB%E4%BA%86&sa=fyb_news&rsv_dl=fyb_news', '7428217', 16, '', '当其他耳机还在卷深度降噪、续航时间、无感佩戴时，有线耳机这个被淘汰了快10年的老物件，反倒被年轻人请了出来。在年轻人看来，无线耳机除了无线，全是缺点；有线耳机除了有线，全是优点。“不用充电、不怕弄丢、不用配对，插上就能听，音质吊打千元头戴式耳机。”', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5398, 'baidu-hot', '广州下暴雨 动物园“落汤狮”走红', 'https://www.baidu.com/s?wd=%E5%B9%BF%E5%B7%9E%E4%B8%8B%E6%9A%B4%E9%9B%A8+%E5%8A%A8%E7%89%A9%E5%9B%AD%E2%80%9C%E8%90%BD%E6%B1%A4%E7%8B%AE%E2%80%9D%E8%B5%B0%E7%BA%A2&sa=fyb_news&rsv_dl=fyb_news', '3497850', 212, '', '3月29日广州遭遇强对流天气，长隆野生动物世界一头非洲雄狮在暴雨中淋雨的视频走红网络。该狮子因鬃毛湿透形成"齐刘海"造型，保持低头静止姿态，被网友赋予“忧郁”“失恋”等创意解读。', '2026-03-31T03:04:13.712Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5417, 'baidu-hot', '3岁女童20秒内还原三阶魔方 破纪录', 'https://www.baidu.com/s?wd=3%E5%B2%81%E5%A5%B3%E7%AB%A520%E7%A7%92%E5%86%85%E8%BF%98%E5%8E%9F%E4%B8%89%E9%98%B6%E9%AD%94%E6%96%B9+%E7%A0%B4%E7%BA%AA%E5%BD%95&sa=fyb_news&rsv_dl=fyb_news', '3295616', 239, '', '近日，延吉3岁小萌娃王玥琛在WRCA认证官见证下，20秒内还原三阶魔方，创造了最小年龄在20秒内还原三阶魔方的WRCA世界纪录。', '2026-03-31T02:04:09.664Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5951, 'baidu-hot', '00后新婚夫妻用摇摇车接亲', 'https://www.baidu.com/s?wd=00%E5%90%8E%E6%96%B0%E5%A9%9A%E5%A4%AB%E5%A6%BB%E7%94%A8%E6%91%87%E6%91%87%E8%BD%A6%E6%8E%A5%E4%BA%B2&sa=fyb_news&rsv_dl=fyb_news', '5132448', 98, '', '3月28日，安徽宿州一对00后新婚夫妻以摇摇车替代传统婚车接亲，因两家距离不足一公里，新郎称此举为避免接亲流程过快，同时实现童年梦想。', '2026-03-31T17:04:28.395Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6104, 'baidu-hot', '女子被未拴绳狗扑倒致骨折获赔17万', 'https://www.baidu.com/s?wd=%E5%A5%B3%E5%AD%90%E8%A2%AB%E6%9C%AA%E6%8B%B4%E7%BB%B3%E7%8B%97%E6%89%91%E5%80%92%E8%87%B4%E9%AA%A8%E6%8A%98%E8%8E%B7%E8%B5%9417%E4%B8%87&sa=fyb_news&rsv_dl=fyb_news', '4546089', 126, '', '近日，北京市密云区居民张女士散步时被邻居赵女士未拴绳的史宾格犬扑倒，导致腰椎、胸椎骨折及九级伤残。赵女士虽垫付部分医疗费，但以张女士患重度骨质疏松为由拒赔剩余款项。经法院调解，判定饲养人需承担无过错责任，最终赔偿17万元。', '2026-03-31T16:04:21.744Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5622, 'baidu-hot', '英语老师手搓AI神器 可批作文管班级', 'https://www.baidu.com/s?wd=%E8%8B%B1%E8%AF%AD%E8%80%81%E5%B8%88%E6%89%8B%E6%90%93AI%E7%A5%9E%E5%99%A8+%E5%8F%AF%E6%89%B9%E4%BD%9C%E6%96%87%E7%AE%A1%E7%8F%AD%E7%BA%A7&sa=fyb_news&rsv_dl=fyb_news', '3804075', 177, '', '近日，武汉十一中一名英语老师自己做了一款“AI神器”引发网友关注。“AI神器”不仅可以批改作业，还可以管理班级、语音测评等，做到了“让老师减负，让学生放心”。', '2026-03-31T01:25:26.445Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6414, 'baidu-hot', '伊朗：愿在诉求满足前提下结束战争', 'https://www.baidu.com/s?wd=%E4%BC%8A%E6%9C%97%EF%BC%9A%E6%84%BF%E5%9C%A8%E8%AF%89%E6%B1%82%E6%BB%A1%E8%B6%B3%E5%89%8D%E6%8F%90%E4%B8%8B%E7%BB%93%E6%9D%9F%E6%88%98%E4%BA%89&sa=fyb_news&rsv_dl=fyb_news', '5696371', 73, '', '当地时间3月31日，伊朗总统佩泽希齐扬表示，伊朗愿意结束战争，但前提是其诉求得到满足，尤其是获得不再遭受侵略的保证。', '2026-03-31T21:04:36.021Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5379, 'baidu-hot', '“脚下就是悬崖 导航还让直行”', 'https://www.baidu.com/s?wd=%E2%80%9C%E8%84%9A%E4%B8%8B%E5%B0%B1%E6%98%AF%E6%82%AC%E5%B4%96+%E5%AF%BC%E8%88%AA%E8%BF%98%E8%AE%A9%E7%9B%B4%E8%A1%8C%E2%80%9D&sa=fyb_news&rsv_dl=fyb_news', '5608882', 78, '', '3月21日，一网友发布视频称自己跟着户外徒步App的引导，抵达关山一处名为“万丈梯”的景点，发现此处山势陡峭，周边未设置防护措施，自己脚下就是悬崖。他表示“腿都吓软了”。', '2026-03-31T09:04:04.143Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5696, 'baidu-hot', '中方：攻击联合国维和人员不能接受', 'https://www.baidu.com/s?wd=%E4%B8%AD%E6%96%B9%EF%BC%9A%E6%94%BB%E5%87%BB%E8%81%94%E5%90%88%E5%9B%BD%E7%BB%B4%E5%92%8C%E4%BA%BA%E5%91%98%E4%B8%8D%E8%83%BD%E6%8E%A5%E5%8F%97&sa=fyb_news&rsv_dl=fyb_news', '3880883', 172, '', '3月31日，外交部发言人毛宁就印尼维和人员在黎巴嫩遇袭一事回应，我们对印尼维和人员遇袭身亡表示深切哀悼，蓄意攻击联合国维和人员严重违反国际人道法和安理会第1701号决议，绝对不能接受。', '2026-03-31T09:04:04.143Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6033, 'baidu-hot', 'U23国足1-0胜越南 杜月徵世界波', 'https://www.baidu.com/s?wd=U23%E5%9B%BD%E8%B6%B31-0%E8%83%9C%E8%B6%8A%E5%8D%97+%E6%9D%9C%E6%9C%88%E5%BE%B5%E4%B8%96%E7%95%8C%E6%B3%A2&sa=fyb_news&rsv_dl=fyb_news', '6097894', 59, '', '北京时间3月31日，CFA中国之队·国际足球锦标赛西安赛第3轮，中国U23对阵越南U23。中国U23杜月徵世界波破门，U23国足1比0取胜。', '2026-03-31T15:04:07.795Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5428, 'baidu-hot', '中国学者遭美盘问后自杀 中领馆发声', 'https://www.baidu.com/s?wd=%E4%B8%AD%E5%9B%BD%E5%AD%A6%E8%80%85%E9%81%AD%E7%BE%8E%E7%9B%98%E9%97%AE%E5%90%8E%E8%87%AA%E6%9D%80+%E4%B8%AD%E9%A2%86%E9%A6%86%E5%8F%91%E5%A3%B0&sa=fyb_news&rsv_dl=fyb_news', '3143264', 257, '', '3月31日，中国驻芝加哥总领馆就中国学者在美遭执法人员约谈盘问后自杀一事发表回应。总领馆对该悲剧深表痛心，我馆负责人已奉命多次就此案向美国政府有关部门和有关高校提出严正交涉。我馆并第一时间同当事人家属取得联系，为家属善后提供积极协助。', '2026-03-31T00:24:20.878Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6823, 'baidu-hot', '2万多网购“小卡宴” 车标要自己贴', 'https://www.baidu.com/s?wd=2%E4%B8%87%E5%A4%9A%E7%BD%91%E8%B4%AD%E2%80%9C%E5%B0%8F%E5%8D%A1%E5%AE%B4%E2%80%9D+%E8%BD%A6%E6%A0%87%E8%A6%81%E8%87%AA%E5%B7%B1%E8%B4%B4&sa=fyb_news&rsv_dl=fyb_news', '7519880', 14, '', '日前，河南一大爷花2万多网购“保时捷小卡宴”，300公里续航实际只能跑50公里，车标都要自己贴，销售还将其微信拉黑。女儿：真服了俺爹啊！目前相关部门已介入。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6660, 'baidu-hot', '张雪机车家乡门店订单已排至6月', 'https://www.baidu.com/s?wd=%E5%BC%A0%E9%9B%AA%E6%9C%BA%E8%BD%A6%E5%AE%B6%E4%B9%A1%E9%97%A8%E5%BA%97%E8%AE%A2%E5%8D%95%E5%B7%B2%E6%8E%92%E8%87%B36%E6%9C%88&sa=fyb_news&rsv_dl=fyb_news', '3622483', 192, '', '当地时间3月28日至29日，张雪机车在世界超级摩托车锦标赛葡萄牙站SSP组别连夺两回合冠军，打破欧美日品牌数十年垄断。记者实探位于张雪家乡湖南怀化的“张雪机车”门店后发现，夺冠后短短两三天内，冠军车型展车已到店，全国购车订单已排至今年6月。', '2026-03-31T22:03:39.330Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5400, 'baidu-hot', '张雪机车一战封神 浙江资本也赢了', 'https://www.baidu.com/s?wd=%E5%BC%A0%E9%9B%AA%E6%9C%BA%E8%BD%A6%E4%B8%80%E6%88%98%E5%B0%81%E7%A5%9E+%E6%B5%99%E6%B1%9F%E8%B5%84%E6%9C%AC%E4%B9%9F%E8%B5%A2%E4%BA%86&sa=fyb_news&rsv_dl=fyb_news', '5044142', 102, '', '继3月30日涨停（20%）后，宏昌科技31日早盘大幅高开。这家以家电零部件为主业的浙江上市公司，近日为何连续大涨？消息面上，或与其间接参股张雪机车有关。而除了宏昌科技之外，张雪机车的背后，还有一众浙江资本的身影。', '2026-03-31T04:04:06.774Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5422, 'baidu-hot', '42岁男子CT报告竟然显示子宫正常', 'https://www.baidu.com/s?wd=42%E5%B2%81%E7%94%B7%E5%AD%90CT%E6%8A%A5%E5%91%8A%E7%AB%9F%E7%84%B6%E6%98%BE%E7%A4%BA%E5%AD%90%E5%AE%AB%E6%AD%A3%E5%B8%B8&sa=fyb_news&rsv_dl=fyb_news', '3516223', 204, '', '近日，有网友发文称，其丈夫CT报告单出错，显示“魏某，男，子宫形态正常”。3月30日，长治医学院附属和平医院发布“情况说明”称，报告书写错误，且未严格审核。目前医院已对涉事相关工作人员进行停职处理，已第一时间向患者及家属诚恳致歉。', '2026-03-31T02:04:09.664Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5623, 'baidu-hot', '外交部揭底日自卫官闯中使馆事件', 'https://www.baidu.com/s?wd=%E5%A4%96%E4%BA%A4%E9%83%A8%E6%8F%AD%E5%BA%95%E6%97%A5%E8%87%AA%E5%8D%AB%E5%AE%98%E9%97%AF%E4%B8%AD%E4%BD%BF%E9%A6%86%E4%BA%8B%E4%BB%B6&sa=fyb_news&rsv_dl=fyb_news', '3240008', 241, '', '3月31日，外交部发言人毛宁在例行记者会上揭底自卫队官员为何持刀闯入中国驻日本大使馆，并表示：事件暴露出日本右翼思想和扭曲历史观的流毒之深、危害之大。', '2026-03-31T03:04:13.712Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5382, 'baidu-hot', '东鹏特饮押宝张雪机车赢麻了', 'https://www.baidu.com/s?wd=%E4%B8%9C%E9%B9%8F%E7%89%B9%E9%A5%AE%E6%8A%BC%E5%AE%9D%E5%BC%A0%E9%9B%AA%E6%9C%BA%E8%BD%A6%E8%B5%A2%E9%BA%BB%E4%BA%86&sa=fyb_news&rsv_dl=fyb_news', '4561329', 125, '', '3月29日，张雪机车在WSBK世界超级摩托车锦标赛葡萄牙站强势夺冠，引发热议。据悉，东鹏特饮此前在网友喊话力荐下已成为张雪机车官方赞助商，网友纷纷点赞东鹏特饮听劝，双向奔赴让世界见证中国品牌的力量。', '2026-03-31T09:04:04.143Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6421, 'baidu-hot', '科学家成功合成新核素锫-235与镅-231', 'https://www.baidu.com/s?wd=%E7%A7%91%E5%AD%A6%E5%AE%B6%E6%88%90%E5%8A%9F%E5%90%88%E6%88%90%E6%96%B0%E6%A0%B8%E7%B4%A0%E9%94%AB-235%E4%B8%8E%E9%95%85-231&sa=fyb_news&rsv_dl=fyb_news', '3711735', 186, '', '近日，近代物理研究所、重离子科学与技术全国重点实验室超重核研究团队与合作者利用兰州重离子加速器国家实验室加速器装置，首次成功合成了新核素锫-235及其阿尔法衰变子核镅-231。', '2026-03-31T19:04:12.827Z');
