INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5776, 'baidu-hot', '邵佳一：我为丢球承担责任', 'https://www.baidu.com/s?wd=%E9%82%B5%E4%BD%B3%E4%B8%80%EF%BC%9A%E6%88%91%E4%B8%BA%E4%B8%A2%E7%90%83%E6%89%BF%E6%8B%85%E8%B4%A3%E4%BB%BB&sa=fyb_news&rsv_dl=fyb_news', '3404058', 223, '', '3月31日，由于在开场9分钟内连丢两球，中国男足在国际足联系列赛第二场比赛中0比2输给了喀麦隆队。赛后，球队主帅邵佳一表示，队员们的表现是满分，他自己为丢球承担责任。', '2026-03-31T16:04:21.744Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5404, 'baidu-hot', '暴雨、冰雹、雷暴大风“组团”来袭', 'https://www.baidu.com/s?wd=%E6%9A%B4%E9%9B%A8%E3%80%81%E5%86%B0%E9%9B%B9%E3%80%81%E9%9B%B7%E6%9A%B4%E5%A4%A7%E9%A3%8E%E2%80%9C%E7%BB%84%E5%9B%A2%E2%80%9D%E6%9D%A5%E8%A2%AD&sa=fyb_news&rsv_dl=fyb_news', '5417505', 87, '', '近期，南方多地降雨连连。31日，大范围降雨和强对流天气仍会持续，广东、福建、浙江等地需防范暴雨；华南地区中北部、江南南部等地的部分地区将有8级以上雷暴大风或冰雹天气。', '2026-03-31T01:25:26.445Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5950, 'baidu-hot', '职高生逆袭清华大学博士后', 'https://www.baidu.com/s?wd=%E8%81%8C%E9%AB%98%E7%94%9F%E9%80%86%E8%A2%AD%E6%B8%85%E5%8D%8E%E5%A4%A7%E5%AD%A6%E5%8D%9A%E5%A3%AB%E5%90%8E&sa=fyb_news&rsv_dl=fyb_news', '3886214', 170, '', '重庆云阳职教中心学生胡涞通过17年努力，从中职起点历经专科、本科、硕博阶段，最终成为清华大学机械工程系博士后，其纳米级精密加工研究突破职业教育天花板。', '2026-03-31T22:40:49.014Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6037, 'baidu-hot', '张雪摩托车封神背后是热爱', 'https://www.baidu.com/s?wd=%E5%BC%A0%E9%9B%AA%E6%91%A9%E6%89%98%E8%BD%A6%E5%B0%81%E7%A5%9E%E8%83%8C%E5%90%8E%E6%98%AF%E7%83%AD%E7%88%B1&sa=fyb_news&rsv_dl=fyb_news', '3314816', 232, '', '3月28日，在世界超级摩托车锦标赛（WSBK）中量级赛事中，法国车手驾驶张雪机车，以领先4秒的碾压式优势夺冠，打破杜卡迪、雅马哈等国际品牌在顶级赛事层面长达数十年的垄断。这一结果，让中国摩托车品牌受到全世界瞩目，也让这个从屋顶漏雨的土坯房走出的汉子受到了全网礼赞。', '2026-03-31T08:04:24.463Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5691, 'baidu-hot', '“只要有图纸 中国100%做得出来”', 'https://www.baidu.com/s?wd=%E2%80%9C%E5%8F%AA%E8%A6%81%E6%9C%89%E5%9B%BE%E7%BA%B8+%E4%B8%AD%E5%9B%BD100%25%E5%81%9A%E5%BE%97%E5%87%BA%E6%9D%A5%E2%80%9D&sa=fyb_news&rsv_dl=fyb_news', '4749895', 116, '', '在世界超级摩托车锦标赛葡萄牙站WorldSSP组别中，中国摩托车制造商“张雪机车”在该站赛事双回合正赛中相继夺冠。面对采访时张雪表示：只要有图纸，中国100%做得出来，而且绝对不比欧、日、美差。', '2026-03-31T18:04:27.648Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5774, 'baidu-hot', '27公里的回家路他走了28年', 'https://www.baidu.com/s?wd=27%E5%85%AC%E9%87%8C%E7%9A%84%E5%9B%9E%E5%AE%B6%E8%B7%AF%E4%BB%96%E8%B5%B0%E4%BA%8628%E5%B9%B4&sa=fyb_news&rsv_dl=fyb_news', '3430567', 218, '', '3月25日，在湖北省建始县公安局会议室，郑顺益夫妇终于见到了失踪28年的儿子阿斌，相认那一刻亲生父母泣不成声。阿斌4岁在家门口走失，养父母家就在邻县，而27公里的回家路他走了28年。', '2026-03-31T17:04:28.395Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6501, 'baidu-hot', '2026第一个蚊子包来了', 'https://www.baidu.com/s?wd=2026%E7%AC%AC%E4%B8%80%E4%B8%AA%E8%9A%8A%E5%AD%90%E5%8C%85%E6%9D%A5%E4%BA%86&sa=fyb_news&rsv_dl=fyb_news', '3298405', 237, '', '“蚊子或将迎来史诗级加强”的消息引发全网关注。近日，不少人已经中招，被叮咬出了2026第一个蚊子包。今年蚊子为何提前上岗？ 据气象监测数据显示，2025—2026年全国大范围出现暖冬天气，北方等多地3月便已发现活跃蚊子，较往年提前1至2个月。', '2026-03-31T22:03:39.330Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5386, 'baidu-hot', '水产专家建议这6种鱼少吃', 'https://www.baidu.com/s?wd=%E6%B0%B4%E4%BA%A7%E4%B8%93%E5%AE%B6%E5%BB%BA%E8%AE%AE%E8%BF%996%E7%A7%8D%E9%B1%BC%E5%B0%91%E5%90%83&sa=fyb_news&rsv_dl=fyb_news', '7136207', 29, '', '近日，上海海洋大学食品学院教授建议，大型肉食性鱼类（如大西洋马鲛鱼）、颜色鲜艳的珊瑚鱼等6类鱼因重金属富集或毒素风险需谨慎食用，优先选择鲳鱼、淡水鲈鱼等低污染鱼种。', '2026-03-31T04:04:06.774Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5856, 'baidu-hot', '税务部门：未发现鞠婧祎涉税问题', 'https://www.baidu.com/s?wd=%E7%A8%8E%E5%8A%A1%E9%83%A8%E9%97%A8%EF%BC%9A%E6%9C%AA%E5%8F%91%E7%8E%B0%E9%9E%A0%E5%A9%A7%E7%A5%8E%E6%B6%89%E7%A8%8E%E9%97%AE%E9%A2%98&sa=fyb_news&rsv_dl=fyb_news', '4946373', 105, '', '国家税务总局上海市税务局稽查局：3月30日，我局收到关于鞠某某涉税事项的实名举报。自2025年9月起，我局多次收到类似举报线索，经认真核查，未发现举报所反映的涉税问题。本次举报是对已经查结的同一检举事项再次检举，且没有提供新的有效线索，依法不予受理。', '2026-03-31T17:04:28.395Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5399, 'baidu-hot', '张桂梅告诉烈士之子：我愿意做你妈妈', 'https://www.baidu.com/s?wd=%E5%BC%A0%E6%A1%82%E6%A2%85%E5%91%8A%E8%AF%89%E7%83%88%E5%A3%AB%E4%B9%8B%E5%AD%90%EF%BC%9A%E6%88%91%E6%84%BF%E6%84%8F%E5%81%9A%E4%BD%A0%E5%A6%88%E5%A6%88&sa=fyb_news&rsv_dl=fyb_news', '5889153', 68, '', '3月30日，“云岭星光”宣讲活动公安民警先进事迹宣讲团走进云南丽江华坪女子高级中学与张桂梅及全校师生温情互动。活动结束后，张桂梅老师拉住烈士之子郑啸云的手动情地说，“你妈妈是好样的，如果你不嫌弃的话，我愿意做你的妈妈。”', '2026-03-31T00:24:20.878Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5415, 'baidu-hot', '疑鞠婧祎收入明细曝光', 'https://www.baidu.com/s?wd=%E7%96%91%E9%9E%A0%E5%A9%A7%E7%A5%8E%E6%94%B6%E5%85%A5%E6%98%8E%E7%BB%86%E6%9B%9D%E5%85%89&sa=fyb_news&rsv_dl=fyb_news', '4371112', 134, '', '3月31日，鞠婧祎被实名举报偷税引发热议，疑鞠婧祎收入明细曝光。举报人列出其2024年6-12月多项商务影视活动，称收入或超5000万元，远高于申报的1100余万元，上海税务已接收举报。', '2026-03-31T00:24:20.878Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6032, 'baidu-hot', '华为2025年销售收入8809亿', 'https://www.baidu.com/s?wd=%E5%8D%8E%E4%B8%BA2025%E5%B9%B4%E9%94%80%E5%94%AE%E6%94%B6%E5%85%A58809%E4%BA%BF&sa=fyb_news&rsv_dl=fyb_news', '5410783', 89, '', '3月31日，华为发布2025年度业绩。全年实现销售收入8809亿人民币，较上一年增长了2.2%。净利润680亿元人民币。2025年研发投入达到1923亿元人民币，约占全年收入的21.8%，近十年累计投入的研发费用超过13820亿元人民币。', '2026-03-31T20:04:10.909Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5625, 'baidu-hot', '租客被房东接表偷电6年才发现', 'https://www.baidu.com/s?wd=%E7%A7%9F%E5%AE%A2%E8%A2%AB%E6%88%BF%E4%B8%9C%E6%8E%A5%E8%A1%A8%E5%81%B7%E7%94%B56%E5%B9%B4%E6%89%8D%E5%8F%91%E7%8E%B0&sa=fyb_news&rsv_dl=fyb_news', '3217011', 249, '', '3月30日，浙江海宁租客‌陈女士‌反映，房东将其它店面电表私接至自家电表，导致6年累计缴纳17多万电费，其中帮房东和他的其余租户多交了几万块。警方已立案，房东承认窃电但拒绝赔偿，并让陈女士‌到期搬走，撤案才能续谈。‌‌', '2026-03-31T01:25:26.445Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6100, 'baidu-hot', '铜师傅上市首日破发 股价跌近50%', 'https://www.baidu.com/s?wd=%E9%93%9C%E5%B8%88%E5%82%85%E4%B8%8A%E5%B8%82%E9%A6%96%E6%97%A5%E7%A0%B4%E5%8F%91+%E8%82%A1%E4%BB%B7%E8%B7%8C%E8%BF%9150%25&sa=fyb_news&rsv_dl=fyb_news', '4081185', 156, '', '3月31日，“铜质文创第一股”杭州铜师傅文创（集团）股份有限公司正式在香港联合交易所主板挂牌上市。然而，其上市首日开盘即破发，铜师傅每股定价60港元，上市首日开盘报35.42港元，较发行价低开40.97%。截至收盘，铜师傅股价报30.5港元/股，跌幅49.17%。', '2026-03-31T21:04:36.021Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6504, 'baidu-hot', '美军一架F-35战机在内华达州坠毁', 'https://www.baidu.com/s?wd=%E7%BE%8E%E5%86%9B%E4%B8%80%E6%9E%B6F-35%E6%88%98%E6%9C%BA%E5%9C%A8%E5%86%85%E5%8D%8E%E8%BE%BE%E5%B7%9E%E5%9D%A0%E6%AF%81&sa=fyb_news&rsv_dl=fyb_news', '3515885', 205, '', '当地时间3月31日，一架美军F-35型隐形战斗机当天在内华达州拉斯维加斯市以北坠毁，飞行员弹射逃生。据悉，这架战机在中午前后曾报告出现操控异常。飞行员弹射后被搜救人员找到，据称有轻微伤势。', '2026-03-31T21:04:36.021Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6415, 'baidu-hot', '美股暴涨 三大股指悉数收高', 'https://www.baidu.com/s?wd=%E7%BE%8E%E8%82%A1%E6%9A%B4%E6%B6%A8+%E4%B8%89%E5%A4%A7%E8%82%A1%E6%8C%87%E6%82%89%E6%95%B0%E6%94%B6%E9%AB%98&sa=fyb_news&rsv_dl=fyb_news', '5130525', 100, '', '截至收盘，道琼斯工业平均指数上涨1125.37点，涨幅2.49%，收于46341.51点。纳斯达克综合指数上涨795.99点，涨幅3.83%，收于21590.63点。标普500指数上涨184.80点，涨幅2.91%，收于6528.52点。', '2026-03-31T20:04:10.909Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6423, 'baidu-hot', '这郁金香的花语是“3块一根5块俩”', 'https://www.baidu.com/s?wd=%E8%BF%99%E9%83%81%E9%87%91%E9%A6%99%E7%9A%84%E8%8A%B1%E8%AF%AD%E6%98%AF%E2%80%9C3%E5%9D%97%E4%B8%80%E6%A0%B95%E5%9D%97%E4%BF%A9%E2%80%9D&sa=fyb_news&rsv_dl=fyb_news', '4835619', 111, '', '近日，烤肠等商品被大家幽默类比为郁金肠，并戏称郁金香的花语是“三块一根五块俩”。网友：我要那朵开的辣椒面最多的！', '2026-03-31T20:04:10.909Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6499, 'baidu-hot', '销冠澳洲优思益实为纯国产 央视曝光', 'https://www.baidu.com/s?wd=%E9%94%80%E5%86%A0%E6%BE%B3%E6%B4%B2%E4%BC%98%E6%80%9D%E7%9B%8A%E5%AE%9E%E4%B8%BA%E7%BA%AF%E5%9B%BD%E4%BA%A7+%E5%A4%AE%E8%A7%86%E6%9B%9D%E5%85%89&sa=fyb_news&rsv_dl=fyb_news', '3617119', 195, '', '随着公众对健康的重视，保健品经常出现在大家的购物车中，特别是一些进口保健品，备受消费者青睐。然而，调查显示，原产地标称为澳大利亚的叶黄素销冠“澳洲优思益”实为纯国产。', '2026-03-31T20:04:10.909Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6580, 'baidu-hot', '半斤19.9元 今年蓝莓怎么这么便宜', 'https://www.baidu.com/s?wd=%E5%8D%8A%E6%96%A419.9%E5%85%83+%E4%BB%8A%E5%B9%B4%E8%93%9D%E8%8E%93%E6%80%8E%E4%B9%88%E8%BF%99%E4%B9%88%E4%BE%BF%E5%AE%9C&sa=fyb_news&rsv_dl=fyb_news', '3124406', 261, '', '近日，有网友发文称，实现蓝莓自由，以前在超市，125克一盒动辄二三十块，现在半斤装才19.9元。今年蓝莓怎么这么便宜？而且还都是大颗粒品种。据悉，这一定程度上是国产蓝莓产业从小众高端向大众普惠转型的阶段性调整。', '2026-03-31T21:04:36.021Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6417, 'baidu-hot', '俄方：伊朗最高领袖目前身在伊朗', 'https://www.baidu.com/s?wd=%E4%BF%84%E6%96%B9%EF%BC%9A%E4%BC%8A%E6%9C%97%E6%9C%80%E9%AB%98%E9%A2%86%E8%A2%96%E7%9B%AE%E5%89%8D%E8%BA%AB%E5%9C%A8%E4%BC%8A%E6%9C%97&sa=fyb_news&rsv_dl=fyb_news', '6568706', 47, '', '当地时间3月31日，俄罗斯驻伊朗大使阿列克谢·杰多夫表示，伊朗最高领袖穆杰塔巴·哈梅内伊目前身在伊朗，但避免公开露面。杰多夫称，正如伊朗领导层多次声明的那样，穆杰塔巴“出于显而易见的原因”避免公开露面。', '2026-03-31T21:04:36.021Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6657, 'baidu-hot', '4月1日起一批国家标准正式实施', 'https://www.baidu.com/s?wd=4%E6%9C%881%E6%97%A5%E8%B5%B7%E4%B8%80%E6%89%B9%E5%9B%BD%E5%AE%B6%E6%A0%87%E5%87%86%E6%AD%A3%E5%BC%8F%E5%AE%9E%E6%96%BD&sa=fyb_news&rsv_dl=fyb_news', '6756983', 43, '', '4月1日起，一批国家标准开始实施，将为引领和规范新兴产业及未来产业的发展、推动传统产业升级、提升交通运输和游览服务质量、保护消费者权益等提供标准支撑。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6101, 'baidu-hot', '女子回应获3亿遗产引丈夫子女不满', 'https://www.baidu.com/s?wd=%E5%A5%B3%E5%AD%90%E5%9B%9E%E5%BA%94%E8%8E%B73%E4%BA%BF%E9%81%97%E4%BA%A7%E5%BC%95%E4%B8%88%E5%A4%AB%E5%AD%90%E5%A5%B3%E4%B8%8D%E6%BB%A1&sa=fyb_news&rsv_dl=fyb_news', '3428487', 219, '', '近日，三亚一六旬男子患肺癌晚期，将3亿家产赠给小28岁的妻子莉女士，引发前妻所育子女不满。据了解，在丈夫重病期间，莉女士始终贴身照料，陪着丈夫完成了5次化疗，她回应称自己一直悉心照顾丈夫，从未主动提过财产。', '2026-03-31T19:04:12.827Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5693, 'baidu-hot', '3秒一架！中国无人机蜂群突击铺天盖地', 'https://www.baidu.com/s?wd=3%E7%A7%92%E4%B8%80%E6%9E%B6%EF%BC%81%E4%B8%AD%E5%9B%BD%E6%97%A0%E4%BA%BA%E6%9C%BA%E8%9C%82%E7%BE%A4%E7%AA%81%E5%87%BB%E9%93%BA%E5%A4%A9%E7%9B%96%E5%9C%B0&sa=fyb_news&rsv_dl=fyb_news', '5517543', 83, '', '近日，中国电科集团发布视频展示国产无人机蜂群系统，该系统采用特种集装箱车，单车可运载48架不同型号无人机，实现3秒一架的无人机蜂群突击。', '2026-03-31T17:04:28.395Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6655, 'baidu-hot', '两只狗偷药：一个打掩护一个负责偷', 'https://www.baidu.com/s?wd=%E4%B8%A4%E5%8F%AA%E7%8B%97%E5%81%B7%E8%8D%AF%EF%BC%9A%E4%B8%80%E4%B8%AA%E6%89%93%E6%8E%A9%E6%8A%A4%E4%B8%80%E4%B8%AA%E8%B4%9F%E8%B4%A3%E5%81%B7&sa=fyb_news&rsv_dl=fyb_news', '5701894', 72, '', '近日，湖南长沙一药店监控拍到“两只狗狗默契配合偷药”的一幕。店员赵女士“还原案发经过”：一只负责打掩护，另一只则叼走药迅速逃跑。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6574, 'baidu-hot', '伊朗将按计划在美国参加世界杯比赛', 'https://www.baidu.com/s?wd=%E4%BC%8A%E6%9C%97%E5%B0%86%E6%8C%89%E8%AE%A1%E5%88%92%E5%9C%A8%E7%BE%8E%E5%9B%BD%E5%8F%82%E5%8A%A0%E4%B8%96%E7%95%8C%E6%9D%AF%E6%AF%94%E8%B5%9B&sa=fyb_news&rsv_dl=fyb_news', '6281578', 56, '', '当地时间3月31日，国际足联主席因凡蒂诺表示，尽管伊朗与世界杯联合主办国美国之间持续发生武装冲突，但伊朗仍将按计划于6月在美国参加世界杯比赛。因凡蒂诺表示，将尽其所能为伊朗队提供支持。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6859, 'baidu-hot', '张雪爆火 这个男人是谁', 'https://www.baidu.com/s?wd=%E5%BC%A0%E9%9B%AA%E7%88%86%E7%81%AB+%E8%BF%99%E4%B8%AA%E7%94%B7%E4%BA%BA%E6%98%AF%E8%B0%81&sa=fyb_news&rsv_dl=fyb_news', '5317456', 93, '', '近日，张雪因其自创品牌张雪机车在‌2026年世界超级摩托车锦标赛（WSBK）葡萄牙站夺冠‌而爆火，其从‌修车学徒到世界冠军制造商‌的逆袭故事也引发广泛共鸣。‌‌他用25年证明：真正撑住一个人的，从来都是死心塌地的热爱。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6500, 'baidu-hot', '“张雪”被全球更多人知道了', 'https://www.baidu.com/s?wd=%E2%80%9C%E5%BC%A0%E9%9B%AA%E2%80%9D%E8%A2%AB%E5%85%A8%E7%90%83%E6%9B%B4%E5%A4%9A%E4%BA%BA%E7%9F%A5%E9%81%93%E4%BA%86&sa=fyb_news&rsv_dl=fyb_news', '4165358', 149, '', '3月31日晚10时许，记者查询谷歌趋势发现，过去7天，“张雪”“张雪机车”在谷歌网页的全球搜索热度快速上涨，在中国、美国、俄罗斯、英国、法国、日本、韩国、加拿大等地区搜索热度均一度达到最高值100。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6822, 'baidu-hot', '西湖景区游客与保安互吐口水', 'https://www.baidu.com/s?wd=%E8%A5%BF%E6%B9%96%E6%99%AF%E5%8C%BA%E6%B8%B8%E5%AE%A2%E4%B8%8E%E4%BF%9D%E5%AE%89%E4%BA%92%E5%90%90%E5%8F%A3%E6%B0%B4&sa=fyb_news&rsv_dl=fyb_news', '3891792', 168, '', '3月31日，有网友发布视频称：杭州西湖景区苏堤一名发小广告的游客被保安多次劝阻无效后发生争执，双方互吐口水。警方介入后游客道歉，管理处对保安进行教育并要求改进处理方式。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7009, 'baidu-hot', '李健曾连发3天短信问许飞要授权', 'https://www.baidu.com/s?wd=%E6%9D%8E%E5%81%A5%E6%9B%BE%E8%BF%9E%E5%8F%913%E5%A4%A9%E7%9F%AD%E4%BF%A1%E9%97%AE%E8%AE%B8%E9%A3%9E%E8%A6%81%E6%8E%88%E6%9D%83&sa=fyb_news&rsv_dl=fyb_news', '3488531', 215, '', '“你不用给钱。”“不行，创作应该得到尊重。”这段对话发生在2017年《歌手》节目筹备期间。当时，李健决想要翻唱许飞的《父亲写的散文诗》，于是发短信询问授权，结果连续三天都没动静，于是其转而跑到微博上给许飞私信留言。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7011, 'baidu-hot', '拼豆爆火 想靠开店翻身的人傻眼了', 'https://www.baidu.com/s?wd=%E6%8B%BC%E8%B1%86%E7%88%86%E7%81%AB+%E6%83%B3%E9%9D%A0%E5%BC%80%E5%BA%97%E7%BF%BB%E8%BA%AB%E7%9A%84%E4%BA%BA%E5%82%BB%E7%9C%BC%E4%BA%86&sa=fyb_news&rsv_dl=fyb_news', '3213099', 251, '', '一批原本并不属于“手工行业”的人，正在用极短的时间开出一家家拼豆店。如果把视角转向拼豆店主，会看到另一层更具体、也更残酷的现实，这是一门被快速复制、迅速内卷的生意，它带来短暂而明确的机会，也带来难以预测的未来。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5619, 'baidu-hot', '陈妍希受伤跟腱断裂 本人回应', 'https://www.baidu.com/s?wd=%E9%99%88%E5%A6%8D%E5%B8%8C%E5%8F%97%E4%BC%A4%E8%B7%9F%E8%85%B1%E6%96%AD%E8%A3%82+%E6%9C%AC%E4%BA%BA%E5%9B%9E%E5%BA%94&sa=fyb_news&rsv_dl=fyb_news', '3142829', 258, '', '3月31日，陈妍希工作室声明称，艺人在30日运动时意外跟腱断裂，目前已完成手术并暂停近期工作；本人回应“请别太担心，我会好好养伤”。', '2026-03-31T14:04:01.165Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6502, 'baidu-hot', '电池有了专属“身份证”', 'https://www.baidu.com/s?wd=%E7%94%B5%E6%B1%A0%E6%9C%89%E4%BA%86%E4%B8%93%E5%B1%9E%E2%80%9C%E8%BA%AB%E4%BB%BD%E8%AF%81%E2%80%9D&sa=fyb_news&rsv_dl=fyb_news', '3234161', 244, '', '4月1日，全国新能源汽车动力电池溯源信息平台正式上线，将为我国新能源汽车产业绿色循环发展提供国家级信息平台支撑。据悉，该平台以动力电池的数字身份信息为核心载体，通过对每一块动力电池进行编码，上线产业链上下游的数据信息，实现了对动力电池流向的链式追溯。', '2026-03-31T21:04:36.021Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5859, 'baidu-hot', '王伟牺牲25周年 墓前摆满中国战机', 'https://www.baidu.com/s?wd=%E7%8E%8B%E4%BC%9F%E7%89%BA%E7%89%B225%E5%91%A8%E5%B9%B4+%E5%A2%93%E5%89%8D%E6%91%86%E6%BB%A1%E4%B8%AD%E5%9B%BD%E6%88%98%E6%9C%BA&sa=fyb_news&rsv_dl=fyb_news', '3596642', 198, '', '今年4月1日是飞行员王伟牺牲25周年纪念日。近日，王伟烈士墓前摆满歼-20、歼-35等中国战机模型。致敬王伟烈士！', '2026-03-31T16:04:21.744Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7008, 'baidu-hot', '张雪机车夺冠：政府该怎样支持企业', 'https://www.baidu.com/s?wd=%E5%BC%A0%E9%9B%AA%E6%9C%BA%E8%BD%A6%E5%A4%BA%E5%86%A0%EF%BC%9A%E6%94%BF%E5%BA%9C%E8%AF%A5%E6%80%8E%E6%A0%B7%E6%94%AF%E6%8C%81%E4%BC%81%E4%B8%9A&sa=fyb_news&rsv_dl=fyb_news', '5131369', 99, '', '据悉，张雪因重庆摩托车产业的强大基础，而选择在重庆开创机车事业，这显然与重庆历届政府在发展摩托车产业方面的努力分不开。政府支持企业，既要为其提供必要的外部条件，也应不断提升自身服务能力，最后，还需与企业保持距离，不打扰企业发展。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6971, 'baidu-hot', '“每天穿什么取决于邻居晒什么”', 'https://www.baidu.com/s?wd=%E2%80%9C%E6%AF%8F%E5%A4%A9%E7%A9%BF%E4%BB%80%E4%B9%88%E5%8F%96%E5%86%B3%E4%BA%8E%E9%82%BB%E5%B1%85%E6%99%92%E4%BB%80%E4%B9%88%E2%80%9D&sa=fyb_news&rsv_dl=fyb_news', '5044665', 101, '', '近日，上海宝山一小区居民晾晒的衣物频繁丢失。警方调取公共视频发现，一男子多次公然盗窃邻居晾晒的衣物。目前，该男子已被依法刑事拘留。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6743, 'baidu-hot', '对迫害大陆配偶的打手帮凶终身追责', 'https://www.baidu.com/s?wd=%E5%AF%B9%E8%BF%AB%E5%AE%B3%E5%A4%A7%E9%99%86%E9%85%8D%E5%81%B6%E7%9A%84%E6%89%93%E6%89%8B%E5%B8%AE%E5%87%B6%E7%BB%88%E8%BA%AB%E8%BF%BD%E8%B4%A3&sa=fyb_news&rsv_dl=fyb_news', '4926954', 109, '', '4月1日，国务院台办发言人张晗在例行新闻发布会上表示：徐春莺是民进党当局司法迫害大陆配偶的又一恶例，我要强调指出，对于侦办审理、司法迫害大陆配偶的打手帮凶，我们将依法惩治、终身追责、绝不宽待。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6970, 'baidu-hot', '立了遗嘱全给女儿 私生子起诉获支持', 'https://www.baidu.com/s?wd=%E7%AB%8B%E4%BA%86%E9%81%97%E5%98%B1%E5%85%A8%E7%BB%99%E5%A5%B3%E5%84%BF+%E7%A7%81%E7%94%9F%E5%AD%90%E8%B5%B7%E8%AF%89%E8%8E%B7%E6%94%AF%E6%8C%81&sa=fyb_news&rsv_dl=fyb_news', '7039984', 33, '', '近日，深圳一男子王先生去世后留下房产、存款等遗产，并立公证遗嘱将除赡养母亲外的财产全归婚生女小王。不料，一名自称王先生非婚生子的男子起诉要求分得遗产。经法院认定，双方亲子关系成立，该男子作为非婚生子，与婚生子女享有同等继承权。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7007, 'baidu-hot', '6月1日起疲劳驾驶认定有新变化', 'https://www.baidu.com/s?wd=6%E6%9C%881%E6%97%A5%E8%B5%B7%E7%96%B2%E5%8A%B3%E9%A9%BE%E9%A9%B6%E8%AE%A4%E5%AE%9A%E6%9C%89%E6%96%B0%E5%8F%98%E5%8C%96&sa=fyb_news&rsv_dl=fyb_news', '6570797', 46, '', '近日，“疲劳驾驶新规即将实施”引发网友关注，2026年2月，公安部正式发布《机动车驾驶人疲劳驾驶认定规则》，新规将于6月1日在全国落地执行，打破“只看驾驶时长”的局限性，以驾驶行为+生理状态+生活轨迹三维立体判定驾驶员是否为疲劳驾驶。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6820, 'baidu-hot', '甲骨文凌晨宣布裁员3万人', 'https://www.baidu.com/s?wd=%E7%94%B2%E9%AA%A8%E6%96%87%E5%87%8C%E6%99%A8%E5%AE%A3%E5%B8%83%E8%A3%81%E5%91%983%E4%B8%87%E4%BA%BA&sa=fyb_news&rsv_dl=fyb_news', '6372711', 54, '', '全球软件巨头甲骨文（Oracle）于当地时间3月31日凌晨向员工群发邮件，宣布启动新一轮大规模裁员。多名员工披露，邮件措辞直白：“我们决定取消您的岗位，今天是您的最后一个工作日。”据悉，此次裁员受影响岗位可能达3万人，约占其全球16.2万员工总数的18%。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6659, 'baidu-hot', '疑用中国风景照 苏格兰撤下旅游广告', 'https://www.baidu.com/s?wd=%E7%96%91%E7%94%A8%E4%B8%AD%E5%9B%BD%E9%A3%8E%E6%99%AF%E7%85%A7+%E8%8B%8F%E6%A0%BC%E5%85%B0%E6%92%A4%E4%B8%8B%E6%97%85%E6%B8%B8%E5%B9%BF%E5%91%8A&sa=fyb_news&rsv_dl=fyb_news', '6001089', 64, '', '当地时间3月28日，据英媒报道，苏格兰政府近日撤下了一张广告图片。原因是公众发现，其中用于推广苏格兰高地旅游的照片，疑似实际拍摄于中国长白山。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6863, 'baidu-hot', '歌手张政直播后突然晕倒被紧急送医', 'https://www.baidu.com/s?wd=%E6%AD%8C%E6%89%8B%E5%BC%A0%E6%94%BF%E7%9B%B4%E6%92%AD%E5%90%8E%E7%AA%81%E7%84%B6%E6%99%95%E5%80%92%E8%A2%AB%E7%B4%A7%E6%80%A5%E9%80%81%E5%8C%BB&sa=fyb_news&rsv_dl=fyb_news', '5890037', 67, '', '3月31日晚，歌手张政在完成直播后突然捂住胸口，对工作人员大喊，“不要碰我，我这里痛”，随后抽搐晕倒，现场人员立即拨打急救电话，张政被救护车送往医院。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6972, 'baidu-hot', '患者做手术需自费买刀 收费近4千元', 'https://www.baidu.com/s?wd=%E6%82%A3%E8%80%85%E5%81%9A%E6%89%8B%E6%9C%AF%E9%9C%80%E8%87%AA%E8%B4%B9%E4%B9%B0%E5%88%80+%E6%94%B6%E8%B4%B9%E8%BF%914%E5%8D%83%E5%85%83&sa=fyb_news&rsv_dl=fyb_news', '4834166', 112, '', '据媒体报道，3月29日，尹女士陪同儿子到医院做完手术结算时，发现有一笔3927.26元的“卫生材料费”，询问后得知是“一次性手术刀”的费用。医院工作人员说，手术用的是进口一次性刀具，“其他病人也是这么收费的”。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6102, 'baidu-hot', '纯牛奶倒出疑似透明苦水？当地通报', 'https://www.baidu.com/s?wd=%E7%BA%AF%E7%89%9B%E5%A5%B6%E5%80%92%E5%87%BA%E7%96%91%E4%BC%BC%E9%80%8F%E6%98%8E%E8%8B%A6%E6%B0%B4%EF%BC%9F%E5%BD%93%E5%9C%B0%E9%80%9A%E6%8A%A5&sa=fyb_news&rsv_dl=fyb_news', '3799187', 178, '', '3月31日，青海省共和县市场监督管理局针对纯牛奶倒出疑似透明苦水一事发布情况通报，称同批次产品召回封存，将全面排查。', '2026-03-31T18:04:27.648Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6497, 'baidu-hot', '伊朗战事终局有几种可能', 'https://www.baidu.com/s?wd=%E4%BC%8A%E6%9C%97%E6%88%98%E4%BA%8B%E7%BB%88%E5%B1%80%E6%9C%89%E5%87%A0%E7%A7%8D%E5%8F%AF%E8%83%BD&sa=fyb_news&rsv_dl=fyb_news', '6094532', 60, '', '美以伊战事持续一个月有余，近期显露和谈迹象。即便和谈举行，战事烈度并非必然随之降低，打打停停、边打边谈以致冲突延宕的可能性犹存。这场战事将有怎样的终局，成为多家智库热议焦点。', '2026-03-31T21:04:36.021Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7388, 'baidu-hot', '起猛了 在成都看到关公开公交', 'https://www.baidu.com/s?wd=%E8%B5%B7%E7%8C%9B%E4%BA%86+%E5%9C%A8%E6%88%90%E9%83%BD%E7%9C%8B%E5%88%B0%E5%85%B3%E5%85%AC%E5%BC%80%E5%85%AC%E4%BA%A4&sa=fyb_news&rsv_dl=fyb_news', '6943976', 37, '', '近日，成都推出“三国寻梦线”主题巴士‌，武侯祠博物馆与公交集团合作，由司机扮成关公形象驾驶双层巴士，汉服NPC全程陪同游客体验三国文化与城市风光。', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7414, 'baidu-hot', '按摩店回应提供1小时免费法律咨询', 'https://www.baidu.com/s?wd=%E6%8C%89%E6%91%A9%E5%BA%97%E5%9B%9E%E5%BA%94%E6%8F%90%E4%BE%9B1%E5%B0%8F%E6%97%B6%E5%85%8D%E8%B4%B9%E6%B3%95%E5%BE%8B%E5%92%A8%E8%AF%A2&sa=fyb_news&rsv_dl=fyb_news', '3718348', 184, '', '南宁市一按摩店因价目表标注“1小时免费法律咨询”引发热议。按摩店回应称确实提供该服务，但需先在店内消费，咨询可在按摩过程中进行，1小时内免费，不消费无法直接咨询。相关情况已被反映至市监局，将进行核查。', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7418, 'baidu-hot', '正直播NBA：凯尔特人vs热火', 'https://www.baidu.com/s?wd=%E6%AD%A3%E7%9B%B4%E6%92%ADNBA%EF%BC%9A%E5%87%AF%E5%B0%94%E7%89%B9%E4%BA%BAvs%E7%83%AD%E7%81%AB&sa=fyb_news&rsv_dl=fyb_news', '3584657', 201, '', '4月2日早上7:30，凯尔特人vs热火。', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7419, 'baidu-hot', '商场半开放男童厕所引质疑 商场回应', 'https://www.baidu.com/s?wd=%E5%95%86%E5%9C%BA%E5%8D%8A%E5%BC%80%E6%94%BE%E7%94%B7%E7%AB%A5%E5%8E%95%E6%89%80%E5%BC%95%E8%B4%A8%E7%96%91+%E5%95%86%E5%9C%BA%E5%9B%9E%E5%BA%94&sa=fyb_news&rsv_dl=fyb_news', '3333458', 230, '', '3月31日，哈尔滨松北万象汇商场因设置半开放式男童厕所引发争议，部分网民质疑该设计侵犯儿童隐私权。4月1日，商场回应称该厕所参考国内成熟案例，旨在培养儿童独立如厕能力，同时方便女性家长引导男童如厕，避免带入异性成人卫生间的不便，强调非强制使用并将增设隐私提示。', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7420, 'baidu-hot', '严屹宽鼓励张凌赫接受质疑', 'https://www.baidu.com/s?wd=%E4%B8%A5%E5%B1%B9%E5%AE%BD%E9%BC%93%E5%8A%B1%E5%BC%A0%E5%87%8C%E8%B5%AB%E6%8E%A5%E5%8F%97%E8%B4%A8%E7%96%91&sa=fyb_news&rsv_dl=fyb_news', '3207805', 254, '', '3月30日，严屹宽在播客访谈中回应《逐玉》“粉底液将军”妆容争议，鼓励搭档张凌赫接受质疑，指出“有质疑说明受关注”，建议其“与自己赛跑”，并引用“天将降大任”勉励对方遵守演员规范，相信未来会升华演技。', '2026-04-01T17:41:34.155Z');
