INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6862, 'baidu-hot', '张本智和全胜晋级淘汰赛', 'https://www.baidu.com/s?wd=%E5%BC%A0%E6%9C%AC%E6%99%BA%E5%92%8C%E5%85%A8%E8%83%9C%E6%99%8B%E7%BA%A7%E6%B7%98%E6%B1%B0%E8%B5%9B&sa=fyb_news&rsv_dl=fyb_news', '7233639', 24, '', '4月1日，张本智和挑战裁判成功。鹰眼挑战显示，张本智和发球角度25度，并未违规！最终，张本智和3-0战胜林文政，两战全胜晋级世界杯淘汰赛。', '2026-03-31T23:05:26.297Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5391, 'baidu-hot', '男孩看望离异母亲遭其同居男友殴打', 'https://www.baidu.com/s?wd=%E7%94%B7%E5%AD%A9%E7%9C%8B%E6%9C%9B%E7%A6%BB%E5%BC%82%E6%AF%8D%E4%BA%B2%E9%81%AD%E5%85%B6%E5%90%8C%E5%B1%85%E7%94%B7%E5%8F%8B%E6%AE%B4%E6%89%93&sa=fyb_news&rsv_dl=fyb_news', '6468905', 52, '', '3月7日，湖北襄阳老河口市一10岁男孩前往母亲住处期间，遭母亲同居男友雷某暴力殴打，致两颗牙齿脱落、唇部受伤，经法医鉴定为轻伤二级。3月30日，目前雷某已被刑拘，警方已将该起故意伤害案移交检方。', '2026-03-31T01:25:26.445Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5388, 'baidu-hot', '空货车“超重”被拦 司机：拉的是空气', 'https://www.baidu.com/s?wd=%E7%A9%BA%E8%B4%A7%E8%BD%A6%E2%80%9C%E8%B6%85%E9%87%8D%E2%80%9D%E8%A2%AB%E6%8B%A6+%E5%8F%B8%E6%9C%BA%EF%BC%9A%E6%8B%89%E7%9A%84%E6%98%AF%E7%A9%BA%E6%B0%94&sa=fyb_news&rsv_dl=fyb_news', '5610963', 77, '', '近日，邱先生驾车经过上海市青浦区的北青公路收费站时被拦下，收费员称电脑显示车辆超重，要求其立即倒车。最终他在打开车厢证明是空车后，收费员才承认错误并予以放行。', '2026-03-31T05:04:26.574Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6505, 'baidu-hot', '玩具店主买卖枪支案两当事人获国赔', 'https://www.baidu.com/s?wd=%E7%8E%A9%E5%85%B7%E5%BA%97%E4%B8%BB%E4%B9%B0%E5%8D%96%E6%9E%AA%E6%94%AF%E6%A1%88%E4%B8%A4%E5%BD%93%E4%BA%8B%E4%BA%BA%E8%8E%B7%E5%9B%BD%E8%B5%94&sa=fyb_news&rsv_dl=fyb_news', '5327001', 91, '', '近日，甘肃武威市凉州区法院向“玩具店主买卖枪支案”当事人聂鹏立、刘新作出国家赔偿决定，两人各获赔16.267万元（含人身自由赔偿金132670.08元及精神抚慰金3万元）。', '2026-03-31T21:04:36.021Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5767, 'baidu-hot', '网传“70岁老人就医新规”不实', 'https://www.baidu.com/s?wd=%E7%BD%91%E4%BC%A0%E2%80%9C70%E5%B2%81%E8%80%81%E4%BA%BA%E5%B0%B1%E5%8C%BB%E6%96%B0%E8%A7%84%E2%80%9D%E4%B8%8D%E5%AE%9E&sa=fyb_news&rsv_dl=fyb_news', '6850924', 39, '', '近日，网传“4月1日起70岁以上老人就医新规”系谣言，上海市卫健委及国家相关部门均否认有此政策发布。', '2026-03-31T19:04:12.827Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (5380, 'baidu-hot', '运动员退役后从146斤暴涨至523斤', 'https://www.baidu.com/s?wd=%E8%BF%90%E5%8A%A8%E5%91%98%E9%80%80%E5%BD%B9%E5%90%8E%E4%BB%8E146%E6%96%A4%E6%9A%B4%E6%B6%A8%E8%87%B3523%E6%96%A4&sa=fyb_news&rsv_dl=fyb_news', '3108933', 265, '', '近日，华东医院收治了一名体重523斤的重度肥胖患者，刷新了此前新华医院515斤小伙"沪上第一胖"的纪录。据悉，今年43岁的周先生，曾是一名体工队运动员，练的是自由摔跤和足球。退伍后，他因脚踝受伤停练以及激素治疗等影响，体重从146斤暴增至523斤。', '2026-03-31T07:04:28.019Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (6420, 'baidu-hot', '张雪20年前采访画面曝光', 'https://www.baidu.com/s?wd=%E5%BC%A0%E9%9B%AA20%E5%B9%B4%E5%89%8D%E9%87%87%E8%AE%BF%E7%94%BB%E9%9D%A2%E6%9B%9D%E5%85%89&sa=fyb_news&rsv_dl=fyb_news', '4754930', 115, '', '近日，张雪20年前的采访画面曝光。19岁的张雪在采访中说：“我并不是想到电视里秀一下，我是真的喜欢摩托车！从小就喜欢摩托车！”', '2026-03-31T21:04:36.021Z');
