INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7387, 'baidu-hot', '“在美出生即公民”或彻底终结', 'https://www.baidu.com/s?wd=%E2%80%9C%E5%9C%A8%E7%BE%8E%E5%87%BA%E7%94%9F%E5%8D%B3%E5%85%AC%E6%B0%91%E2%80%9D%E6%88%96%E5%BD%BB%E5%BA%95%E7%BB%88%E7%BB%93&sa=fyb_news&rsv_dl=fyb_news', '7524374', 10, '', '当地时间4月1日，美国最高法院将正式就“出生公民权”案举行口头辩论。这场世纪诉讼源自特朗普上任签署的第14160号行政令——该令试图推翻自1868年确立、已延续158年的“凡在美出生即为公民”铁律。', '2026-04-01T17:41:34.155Z');
