INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7390, 'baidu-hot', '青岛保时捷女销售再夺第一季度销冠', 'https://www.baidu.com/s?wd=%E9%9D%92%E5%B2%9B%E4%BF%9D%E6%97%B6%E6%8D%B7%E5%A5%B3%E9%94%80%E5%94%AE%E5%86%8D%E5%A4%BA%E7%AC%AC%E4%B8%80%E5%AD%A3%E5%BA%A6%E9%94%80%E5%86%A0&sa=fyb_news&rsv_dl=fyb_news', '6286394', 55, '', '青岛保时捷女销售再夺2026年第一季度销冠。4月1日，青岛保时捷销售牟倩文molly发文：“3月上旬几乎不卖车，下旬才开始发力，追回了销冠，人生也许就是这样，只要坚持做对的事情，结果一定是好的，4月加油。”', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7391, 'baidu-hot', '男子山上挖野菜挖到超大地黄', 'https://www.baidu.com/s?wd=%E7%94%B7%E5%AD%90%E5%B1%B1%E4%B8%8A%E6%8C%96%E9%87%8E%E8%8F%9C%E6%8C%96%E5%88%B0%E8%B6%85%E5%A4%A7%E5%9C%B0%E9%BB%84&sa=fyb_news&rsv_dl=fyb_news', '6190698', 57, '', '近日，一名男子在山上挖野菜时意外挖到超大地黄，其根茎异常粗壮，引发关注。有网友回忆童年时常吸食地黄花的经历。', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7389, 'baidu-hot', '老人存10万取钱只有7万 银行回应', 'https://www.baidu.com/s?wd=%E8%80%81%E4%BA%BA%E5%AD%9810%E4%B8%87%E5%8F%96%E9%92%B1%E5%8F%AA%E6%9C%897%E4%B8%87+%E9%93%B6%E8%A1%8C%E5%9B%9E%E5%BA%94&sa=fyb_news&rsv_dl=fyb_news', '6084379', 62, '', '近日，市民郭女士反映，其父母在中信银行焦作分行被误导，将近10万元“养老储蓄”办成保险，退保将损失3万余元只剩7万。银行回应称已履行风险告知义务、销售流程合规，但郭女士不认可，双方仍有争议，老人可依法维权。', '2026-04-01T17:41:34.155Z');
