INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7392, 'baidu-hot', '有线耳机被淘汰10年翻红 销量暴涨20%', 'https://www.baidu.com/s?wd=%E6%9C%89%E7%BA%BF%E8%80%B3%E6%9C%BA%E8%A2%AB%E6%B7%98%E6%B1%B010%E5%B9%B4%E7%BF%BB%E7%BA%A2+%E9%94%80%E9%87%8F%E6%9A%B4%E6%B6%A820%25&sa=fyb_news&rsv_dl=fyb_news', '5890700', 66, '', '近日，被淘汰了快10年的有线耳机意外走红，成为耳机圈最受关注的现象级产品。调研机构Circana报告显示，有线耳机在经历长达5年销售下滑后强势反弹，2026年前三个月销售额暴涨20%。', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7410, 'baidu-hot', '3台旧手机能换1台iPhone？实地调查', 'https://www.baidu.com/s?wd=3%E5%8F%B0%E6%97%A7%E6%89%8B%E6%9C%BA%E8%83%BD%E6%8D%A21%E5%8F%B0iPhone%EF%BC%9F%E5%AE%9E%E5%9C%B0%E8%B0%83%E6%9F%A5&sa=fyb_news&rsv_dl=fyb_news', '5807497', 69, '', '最近社交平台不少帖子称废旧手机回收价走高，行情火爆甚至有自媒体表示“三台旧手机能换一台iPhone”。连日来记者走访上海二手手机回收市场发现，网传说法严重夸大除了个别安卓机型回收价有所波动，大部分手机的回收价格并不高。', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7396, 'baidu-hot', '女子隐瞒重病订婚向男友要600万治病', 'https://www.baidu.com/s?wd=%E5%A5%B3%E5%AD%90%E9%9A%90%E7%9E%92%E9%87%8D%E7%97%85%E8%AE%A2%E5%A9%9A%E5%90%91%E7%94%B7%E5%8F%8B%E8%A6%81600%E4%B8%87%E6%B2%BB%E7%97%85&sa=fyb_news&rsv_dl=fyb_news', '5695745', 74, '', '4月1日，河南一女子隐瞒患有尿毒症，经人介绍与男子相亲两天后订婚，并要求男方贷款600万治病，被拒绝后拉黑对方。法院判决：女方返还70%彩礼。', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7395, 'baidu-hot', '李连杰首度回应拍短剧原因', 'https://www.baidu.com/s?wd=%E6%9D%8E%E8%BF%9E%E6%9D%B0%E9%A6%96%E5%BA%A6%E5%9B%9E%E5%BA%94%E6%8B%8D%E7%9F%AD%E5%89%A7%E5%8E%9F%E5%9B%A0&sa=fyb_news&rsv_dl=fyb_news', '5611634', 76, '', '3月31日晚，在短剧演员穿越李连杰功夫宇宙见面会结束后，李连杰接受记者采访，首度回应拍短剧原因，想打造功夫短剧宇宙，为更多喜欢功夫和武侠的年轻人圆梦。', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7398, 'baidu-hot', '黄子韬自曝不拍戏原因', 'https://www.baidu.com/s?wd=%E9%BB%84%E5%AD%90%E9%9F%AC%E8%87%AA%E6%9B%9D%E4%B8%8D%E6%8B%8D%E6%88%8F%E5%8E%9F%E5%9B%A0&sa=fyb_news&rsv_dl=fyb_news', '5521156', 82, '', '据4月1日网友爆料，黄子韬在直播里的一番“真心话”，直接把自己送上了热搜。他坦言自己现在“基本会少少少上一些”娱乐圈的工作，原因很简单：拍戏一进组就是三四个月，他有点“扛不住”了。', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7397, 'baidu-hot', '奇瑞00后女员工实名举报高管性骚扰', 'https://www.baidu.com/s?wd=%E5%A5%87%E7%91%9E00%E5%90%8E%E5%A5%B3%E5%91%98%E5%B7%A5%E5%AE%9E%E5%90%8D%E4%B8%BE%E6%8A%A5%E9%AB%98%E7%AE%A1%E6%80%A7%E9%AA%9A%E6%89%B0&sa=fyb_news&rsv_dl=fyb_news', '5410553', 90, '', '近日，奇瑞一名“00后”女员工实名举报公司管理人员江某某对其性骚扰，并称其长期作风专横。日前，奇瑞公司回应称，已成立专项调查组核实，并于3月31日对涉事人员作出免职并解除劳动合同的处理，绝不姑息。​​​​', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7405, 'baidu-hot', '小伙赛前订张雪机车 提车乐开花', 'https://www.baidu.com/s?wd=%E5%B0%8F%E4%BC%99%E8%B5%9B%E5%89%8D%E8%AE%A2%E5%BC%A0%E9%9B%AA%E6%9C%BA%E8%BD%A6+%E6%8F%90%E8%BD%A6%E4%B9%90%E5%BC%80%E8%8A%B1&sa=fyb_news&rsv_dl=fyb_news', '5324607', 92, '', '一名年轻男子在WSBK赛事前订购张雪500M机车并于4月1日提车，表示首次购车体验满意。店员介绍现在订单量飙升排期较长。', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7402, 'baidu-hot', '弟弟控诉妈妈区别对待 哥哥回复获赞', 'https://www.baidu.com/s?wd=%E5%BC%9F%E5%BC%9F%E6%8E%A7%E8%AF%89%E5%A6%88%E5%A6%88%E5%8C%BA%E5%88%AB%E5%AF%B9%E5%BE%85+%E5%93%A5%E5%93%A5%E5%9B%9E%E5%A4%8D%E8%8E%B7%E8%B5%9E&sa=fyb_news&rsv_dl=fyb_news', '5224424', 94, '', '', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7399, 'baidu-hot', '“为搭首班车 可以不睡觉！”', 'https://www.baidu.com/s?wd=%E2%80%9C%E4%B8%BA%E6%90%AD%E9%A6%96%E7%8F%AD%E8%BD%A6+%E5%8F%AF%E4%BB%A5%E4%B8%8D%E7%9D%A1%E8%A7%89%EF%BC%81%E2%80%9D&sa=fyb_news&rsv_dl=fyb_news', '5135465', 97, '', '3月29日上午10点57分，由中国中车青岛四方制造的国产“Q-train”列车在港铁荃湾线首航。上百名香港青年彻夜守候，高呼“为搭首班车可以不睡觉”，现场用手机记录这一历史性时刻。', '2026-04-01T17:41:34.155Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7401, 'baidu-hot', '印尼马鲁古海峡发生7.4级地震', 'https://www.baidu.com/s?wd=%E5%8D%B0%E5%B0%BC%E9%A9%AC%E9%B2%81%E5%8F%A4%E6%B5%B7%E5%B3%A1%E5%8F%91%E7%94%9F7.4%E7%BA%A7%E5%9C%B0%E9%9C%87&sa=fyb_news&rsv_dl=fyb_news', '5021611', 104, '', '中国地震台网正式测定：04月02日06时48分在印尼马鲁古海峡（北纬1.20度，东经126.35度）发生7.4级地震，震源深度30千米。', '2026-04-01T17:41:34.155Z');
