INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7130, 'tencent-hot', '医保基金监管新规今起施行：重点打击“车接车送”等骗保方式，重点打击倒卖“回流药”', 'https://view.inews.qq.com/a/20260401A035DE00', '1600352', 34, '', '据新华社，4月1日，《医疗保障基金使用监督管理条例实施细则》（简称《实施细则》）正式施行。3月31日，在国家医保局召开的新闻发布会上，国家医保局副局长黄华波指出，《实施细则》的颁布实施，有利于提高医保基金监管精细化水平，更好地打击违法违规使用医保基金和欺诈骗保行为，提升医保治理效能。国家医保局将以此为契...', '2026-04-01T01:37:51.500Z');
INSERT INTO "items" ("id", "node_hashid", "title", "url", "hot_value", "rank", "thumbnail", "description", "created_at") VALUES (7164, 'tencent-hot', '辽宁第8位外援出炉：签NBA落选秀内线勒迪 已用完换外援名额', 'https://view.inews.qq.com/a/20260401A053T200', '1653533', 28, '', '北京时间4月1日，辽宁最近5场只有2胜3负战绩，内线实力薄弱成为球队的短板。如今根据最新报道，辽宁已经签约本赛季球队第8位外援杰登·勒迪，他是一位内线大外援，曾是NBA落选秀，而辽宁会裁掉哪位现有外援还是未知数，辽宁也是用完本赛季换外援的名额。辽宁目前的四外援阵容，分别是威尔斯、莫兰德、哈维与布罗金顿，其中...', '2026-04-01T01:45:29.761Z');
